INSERT INTO ref_item_attachments
  (key, name, description, type, hp_required, price, rarity, category_limits, base_mods, added_mods, source)
VALUES
  ('AMPHMOD', 'Amphibious Modification', 'Amphibious Modification Many worlds are covered in cast oceans and no few species have evolved in aquatic environments. For those sentients without the evolutionary adaptation of gills, specialized equipment is necessary. With the addition of a sealed helmet and oxygen (or other appropriate gas) supply, nearly any suit of armor can be converted into an amphibious suit. Retractable flippers provide humanoids with improved mobility in water and other liquids. This attachment can be applied to any armor that could logically have an air tank attached. Models Include:Gandorthal Atmospherics Submerible 9, BioTech Mk. II Air Supply', 'Armor', 1, 500, 4, ARRAY['Sealable','Sealed']::text[], '[{"key":null,"count":1,"misc_desc":"Provides up to five hours of oxygen in submersive or airless environments.  Does not protect against vacuum."},{"key":null,"count":1,"misc_desc":"Removes [SE] from physical checks due to underwater conditions."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Increase oxygen supply by two hours"}]'::jsonb, NULL),
  ('ARMINS', 'Armor Insert', 'Armor Insert Armor inserts are thin, flexible, plasteel and ballistic gel plates that can be sewn into clothing to give the wearer concealed armor protection. They can be added to any garment that is suitably large and alter- able, and they can be installed by any skilled tailor for a moderate fee. This attachment can be applied to any armor with a defense no greater than 0 and a soak of 1 or less. Models Include: Creshaldyne "Slimline" Armor Plates.', 'Armor', 0, 450, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Turns any article of clothing into armored clothing."},{"key":null,"count":1,"misc_desc":"Characters can notice the inclusion of armor inserts in clothing by making an [B]Average ([DI][DI]) Perception check[b]."},{"key":"SOAKSET","count":1,"misc_desc":null},{"key":"DEFSET","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Armor inserts can be noticed by making an [B]Average ([DI][DI]) Perception check[b]."}]'::jsonb, '[{"key":"SOAKADD","count":1,"misc_desc":null},{"key":"DEFADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Increase difficulty of check to notice inclusion to [B]Hard([DI][DI][DI])[b]"}]'::jsonb, NULL),
  ('ARMSPIKE', 'Armor Spikes', 'Armor Spikes While armor serves a largely defensive role for its wearers, that needn''''t be the rule. With the addition of spikes, blades, and other protrusions on areas covering shoulders, knuckles, feet, knees or elbows, armor can be turned into a deadly weapon of last resort. The majority of such modifications are scratch-built, though a handful o f armor manufacturers mass-produce kits for the armor sets they sell. Largely popular with criminals, mercenaries, and bounty hunters, armor spikes lend an intimidating mien to anyone equipped with them. Some professionals prefer to keep such deadly modifications concealed and retractable, and these are perhaps the most dangerous of them all. This attachment can be attached to any armor that covers the arms or legs.', 'Armor', 3, 500, 2, ARRAY['Full Body','Half Body']::text[], '[{"key":"ENCADD","count":2,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When wearer suffers a hit from a Melee, Brawl, or Lightsaber combat check, may spend [TH][TH][TH] or [DE] to inflict one hit for 6 damage on attacker."}]'::jsonb, '[{"key":null,"count":3,"misc_desc":"Increase damage to attacker by +1"},{"key":"INTIM","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('AUGSPIN', 'Augmented Spin Barrel', 'Augmented Spin Barrel Using an updated and streamlined galven pattern and heavy-duty static pulse adapters, this custom barrel increases both the damage output and armor penetration of blaster rifles and heavy blaster rifles. The trade-off for all this extra stopping power is increased wear and tear on both the frame of the blaster and the barrel, leading to an increase in maintenance and down-time. This attachment can only be used with blaster rifles and heavy blaster rifles. Models Include: Dolmax 243X "Penetrator Augmented Spin Barrel, Arakyd HH780 HotShot Barrel, BlasTech Model 213 Perforator Barrel.', 'Weapon', 2, 1750, 4, ARRAY['Blaster Rifle','Heavy Blaster Rifle']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Add [SETBACK] to all Mechanics checks when performing\r\n          maintenance on this weapon."}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"ACCURATE","count":1,"misc_desc":null},{"key":"PIERCE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('AUTOWEAPMOUNT', 'Automated Weapon Mounting', 'Automated Weapon Mounting Used by elite special forces across the galaxy-and the occasional bounty hunter-an automated weapon mounting is a sophisticated pseudocybernetic that allows the user to fire a blaster or other handheld weapon while keeping both hands free, possibly for additional weapons. Automated harnesses are most commonly shoulder mounted, although a variety of models are available, some incorporating articulated appendages of up to a half meter in length. Sappers and combat engineers often find automated weapon mountings particularly useful , particularly when combined with a droid brain targeting system, as the mountings allow them to effect battlefield repairs without leaving themselves vulnerable. An automated weapon mounting may be activated by voice or neural link. For obvious reasons, these attachments are rarely seen outside of a battlefield, and they are outlawed on most worlds. A weapon must also be modified in order to be armor-mounted, requiring one hard point.', 'Armor', 2, 3000, 5, NULL, '[{"key":"MOUNT3","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Once per encounter, may spend maneuver to make a combat action with mounted weapon.  Difficulty of check is upgraded once."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add [SE] to combat check instead of upgrading difficulty."},{"key":"MOUNTADDL","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BALHILT', 'Balanced Hilt', 'Balanced Hilt Balance is key in a well-constructed melee weapon. Professional weaponsmiths can use modem ultra-light materials to create a sword or axe that is not only lighter, but also more accurate in the hands of a skilled warrior. This attachment can be used with any melee weapon. Models Include: None.', 'Weapon', 2, 1500, 5, NULL, '[{"key":"ACCURATE","count":1,"misc_desc":null}]'::jsonb, '[{"key":"ENCSUB","count":1,"misc_desc":null},{"key":"ACCURATE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('BARABLS', 'Barab Ingot', 'Barab Ingot Rare variants of kyber crystals unique to the heavily irradiated world Barab I, home of the saurian Barabel people, Barab ingots are among the various crystals used in lightsabers. Found in small clusters in mountainous regions, Barab ingots are hot to the touch and glow with a fierce inner light. When installed in a lightsaber, they create a searing, fiery blade that bums so fiercely that it nearly loses cohesion. A lightsaber with an installed Barab ingot is slightly radioactive, and with a particularly good or lucky strike can set a target alight. A Barab ingot is a lightsaber crystal. Models Include: None', 'Weapon', 2, 15000, 8, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":8,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"BURN","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null}]'::jsonb, '[{"key":"BURN","count":2,"misc_desc":null},{"key":"VICIOUS","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BEAMSPLIT', 'Beam Splitter', 'Beam Splitter Alliance troopers typically apply this upgrade to blaster pistols and other sidearms to achieve results similar to that of the spread barrel used on larger, more powerful blasters. Beam splitters function by modifying the Galven pattern and carefully mounting three or more emitters into a honeycomb configuration inside a stock blaster barrel. Shots fired from a weapon with this modification diffuse into a weaker, spread shot rather than the typical blaster bolt, giving a single shot the potential to connect with multiple targets. Rebel troops often use this upgrade to transform weaponry into effective standoff weapons used to pin down enemy troops and hold chokepoints in narrow starship corridors. This attachment can be applied to any blaster or suitable energy weapon that does not have the Blast quality.', 'Weapon', 3, 1250, 5, NULL, '[{"key":"BLAST","count":1,"misc_desc":null},{"key":"RANGESUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DISORIENT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BIOFEED', 'Biofeedback System', 'Biofeedback System This system closely monitors the vital signs of the person wearing the armor. It can immediately identify when the user is hurt or experiencing elevated levels of adrenaline and administer minor sedatives, healing chemicals, and other drugs as needed. This attachment can be installed on any full-body armor suit. Models Include: BioTech "Autodoc" Monitoring Network, Atlas Corp NG-7 Vital System.', 'Armor', 2, 3300, 5, ARRAY['Full Body']::text[], '[{"key":"STRAINADD","count":4,"misc_desc":null}]'::jsonb, '[{"key":"RAPREC","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('BIPOD', 'Bipod Mount', 'Bipod Mount Little more than a pair of folding or collapsible legs mounted beneath the barrel of a long arm, bipods are used to stabilize awkward or heavy weapons to improve their firing characteristics. Especially useful when firing from behind low cover or from a prone position, bipods are typically used on squad support weapons, or by sharpshooters and snipers to better steady their weapons. This attachment can only be applied to rifles, carbines, and light repeating blasters, and takes one preparation maneuver to set up. Models Include: Galactic Arms XA Classic Bipod, Czerka M20 Marksman Bipod.', 'Weapon', 1, 100, 1, ARRAY['Rifle','Heavy Rifle','Carbine']::text[], '[{"key":"CUMBERSOME","count":-2,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('BLADEDRAIN', 'Blade Drain', 'Blade Drain The Blade drain attachment works by creating a small power drain when in contact with another lightsaber blade. Once attached to a lightsaber hilt and wired into the power supply, the blade drain attachment draws energy from the power supply of an opponent''''s lightsaber via the energy blade contact is made. The draw is momentary but significant enough to reduce the effectiveness of an opponent''''s lightsaber, making it less capable of dealing damage. There is, however, a risk that the drawn power could overload the power supply of the wielder''''s own lightsaber as the excess power is stored, causing a catastrophic failure in the device. Users of this modification consider it a small price to pay for reducing the combat effectiveness of their foes, a trade off that could save lives. This attachment can only be applied to lightsabers.', 'Weapon', 2, 4000, 9, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":null,"count":1,"misc_desc":"When making a combat check targeting an opponent with a lightsaber, character may spend [TR] to reduce opponent''s lightsaber''s base damage by one for remainder of encounter."},{"key":null,"count":1,"misc_desc":"[TH][TH][TH] causes blade to collapse.  Cannot be reignited until character''s next turn."}]'::jsonb, '[{"key":"DEFENSIVE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BLASTACT', 'Blaster Actuating Module', 'Blaster Actuating Module A Blaster Actuating Module is a blaster modification popular with mercenaries, bounty hunters, and anyone needing to make the first strike count. Adaptable to nearly any blaster pistol, this attachment is a simple upgraded blaster actuating module with custom firmware and a stronger electromagnetic accelerator that provides more powerful and more penetrating blaster shots. Unfortunately, this excess power takes its toll on the weapon, and blasters so modified tend to develop reliability problems the longer they are used with this attachment. This attachment is only for use on Ranged (Light) blaster pistols. Models Include: SoroSuub X440 "Hammer Blaster Actuating Module, Dolmax Heavy Blaster Actuator, Arakyd 97R Enhanced Blaster Actuating Module.', 'Weapon', 1, 500, 4, ARRAY['Blaster Pistol','Heavy Blaster Pistol']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"SETBACKADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"PIERCE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BLASTDAMP', 'Blaster Energy Dampener', 'Blaster Energy Dampener A blaster, with its focused energy, is one of the most powerful ranged weapons, but those who wish to conceal their shots are often forced to resort to other weapons if they want to pass unnoticed. Some assassins and spies prefer a blaster energy dampener, an attachment that significantly reduces the visibility of a blaster bolt, at the cost of stopping power. While dampened blaster fire is still noticeable in totally dark or very dim environments, an assassin can make a shot in a well-lit environment and not worry about attracting too much attention. This attachment is only for use on Ranged (Light) and Ranged (Heavy) blaster weapons. Models Include: Czerka B78 Energy Dampener.', 'Weapon', 1, 750, 4, ARRAY['Blaster']::text[], '[{"key":null,"count":1,"misc_desc":"Increases the difficulty of checks made to detect this weapon''s fire by one"},{"key":"DAMSUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add [SE] to checks made to detect this weapon''s fire"}]'::jsonb, NULL),
  ('BLASTSIGHT', 'Built-In Blaster Sight', 'Built-In Blaster Sight A typical modification used by the Rebellion’s SpecForce troops, this attachment allows a harmless beam of energy to trickle out of the barrel on a half-trigger pull to "paint” the target, letting the wielder see exactly where she is aiming Most models illuminate beams in the human visual spectrum, but some use light wavelengths invisible to the naked eye, which require special goggles to spot, to ensure the agent''''s position remains uncompromised. This attachment can only be applied to energy ranged weapons.', 'Weapon', 1, 150, 4, NULL, '[{"key":null,"count":null,"misc_desc":"Remove [SE] added by the Called Shot use of the Aim maneuver from Ranged Light and Ranged Heavy checks."}]'::jsonb, NULL, NULL),
  ('BLASTSUPP', 'Blaster Suppressor', 'Blaster Suppressor Though generally not as loud as slugthrowers, blasters usually emit an audible crack or zap upon being fired. While military scouts and snipers are usually more concerned that a blaster bolt flash might give away their position or disrupt their night vision, those who operate in the galactic underworld often find the report of a blaster to be more troublesome. In order to address this issue, several arms manufacturers produce sound suppressors for a blaster muzzle, making the blaster virtually silent. This attachment can only be used with blaster pistols. Models Include: Merr-Sohn DS9 Blast Suppressor, Czerka "Whispershot" Silencer.', 'Weapon', 1, 750, 5, ARRAY['Blaster Pistol']::text[], '[{"key":null,"count":1,"misc_desc":"Adds [SETBACK][SETBACK] to Perception or Vigilance checks made to locate a concealed shooter firing silenced blaster."}]'::jsonb, NULL, NULL),
  ('BOOTBLADE', 'Boot Blade', 'Boot Blade An excellent way to ensure an agent is always armed no matter the circumstances, boot blades are small spring-loaded knives that extend from the toes of an individual''''s shoes or boots to provide an extra edge in hand-to-hand combat. There are various ways to deploy the blades, such as pressing a certain point on the tongue of a shoe or stamping hard with a boot''''s heel. Retracting them often entails simply (but carefully) pushing them back into their compartment until they catch. This attachment can be applied to any armor that includes boots, shoes, or other footwear. Models Include: Various models.', 'Armor', 0, 100, 5, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"Reduce the weapon''s critical rating by 1 to a minimum of 1"},{"key":null,"count":2,"misc_desc":"Item Quality (Pierce +1)"},{"key":null,"count":1,"misc_desc":"Item Quality (Vicious +1)"}]'::jsonb, NULL),
  ('BOWACC', 'Bowcaster Accelerator Enhancement', 'Bowcaster Accelerator Enhancement Built from scavenged blaster parts and the occasional piece from a repulsorlift generator, the bowcaster accelerator enhancement is the second-most common modification to Wookiee bowcasters after the automatic re-cocker. Essentially an upgrade of the weapon''''s bolt accelerators, this attachment allows the bowcaster to fire its highly destructive quarrels with more force than typical in a stock weapon. These attachments are only for use on Wookiee bowcasters, and they cannot be purchased; they must be built either by the owner of the bowcaster with an Average () Mechanics check or the weaponsmith who built the weapon for him. Models Include: None.', 'Weapon', 1, 250, 4, ARRAY['Bowcaster']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"PIERCE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('BOWREC', 'Bowcaster Re-Cocker', 'Bowcaster Re-Cocker Few weapons in the galaxy are as indicative of their users as the Wookiee bowcaster. Bowcasters require an incredible level of raw physical strength to wield, especially when loading and cocking the weapon to fire. A time-consuming and labor-intensive process, reloading a bowcaster is made much simpler and easier by use of the automatic re-cocker. This attachment entails upgrading the basic weapon with a number of power-assist systems as well as a magazine feed system that allows the weapon to fire, re-cock, and reload all in one smooth, quick movement. These attachments are only for use on Wookiee bowcasters, and they cannot be purchased; they must be built either by the owner of the bowcaster with an Average () Mechanics check or the weaponsmith who built the weapon for him. Models Include: None.', 'Weapon', 1, 500, 3, ARRAY['Bowcaster']::text[], '[{"key":null,"count":1,"misc_desc":"Removes reloading maneuver requirement from bowcaster."}]'::jsonb, '[{"key":"AUTOFIRE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('CCARRAY', 'Cyclic Crystal Array', 'Cyclic Crystal Array Lightsabers rely on kyber crystals attuned to the wielder to create energy blades of different types. Under normal circumstances, swapping out one crystal for another is an arduous process requiring the lightsaber to be disassembled first. Unsatisfied with this situation, a handful of enterprising (if unorthodox) Force users have created attachments that allow for two (or more) crystals to be installed in a single lightsaber. With the press of a button, one crystal is swapped for another, granting unprecedented versatility to lightsaber wielders looking for additional functionality from their otherwise traditional weapon. This attachment can only be applied to lightsabers.', 'Weapon', 2, 1500, 8, ARRAY['Lightsaber']::text[], '[{"key":"ADDCRYSTNC","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When lightsaber is ignited, may choose which active crystal to use.  If already ignited, activating another crystal requires a maneuver."}]'::jsonb, '[{"key":"ADDCRYSTNC","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('COMPALTERWEAPON', 'Component Alteration (Weapon)', 'Component Alteration (Weapon) A more drastic, but more effective, option is to alter a weapon or other device so that it can be broken down into several smaller parts that can be reassembled later. This method is typically used when a Rebel needs to get a larger item into a secure location or to avoid scanning devices that are likely to detect standard weapons regardless of any concealment alterations. This is called a component alteration. Characters wishing to break a weapon or other item down into several parts in this fashion need to spend time dismantling the device into smaller components. This requires a Hard () Mechanics check and takes a number of hours equal to the item''''s encumbrance, or a minimum of one hour. If the check is successful, the device is broken down into a number of components equal to its encumbrance plus 1. So, a blaster pistol is broken down into two components, while a blaster rifle is broken down into five. Note that this differs from the more advanced componentization weapon attachment, which requires no check for use once it is installed and is designed to allow the user to openly carry a weapon, rather than consisting of a simple mechanical disassembly. Characters can try, though, to use component alteration to physically disguise these individual parts to look like code cylinders, comlinks, fusion lanterns, and other mundane objects. While this allows a part to take on the rough appearance of the desired object, it does not gain the functionality of that object. This is generally a taxing and tricky process, and so upgrades the difficulty of the Mechanics check once or more as per the GM''''s discretion. Each or on the initial Mechanics check lets a character carrying the components from a component alteration add to opposed Stealth vs. Perception checks when an observer attempts to notice the true nature of the disassembled device. If the component alteration was designed to make the items appear mundane, he gains instead. Assembling a weapon or other item with a component alteration requires two maneuvers or two minutes of narrative time per component, and the character must make an Average () Mechanics check. All components must be present to make the check. Failure means the components are damaged and the device requires a major repair to be properly reassembled again and returned to function. Component alterations have a strong impact on a item''''s reliability, as most weapons or other complex devices simply aren''''t meant to be broken down into smaller pieces and reassembled. The GM may spend as when a character makes a skill check while using an item with this alteration. A character can only attempt a component alteration once on a given item, and doing so permanently reduces the item''''s available hard points by 1. Items that have no hard points may still be altered in this fashion.', 'Weapon', 0, NULL, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"Characters wishing to break a weapon or other item down into several parts in this fashion need to spend time dismantling the device into smaller components. This requires a [B]Hard ([DI][DI][DI]) Mechanics check[b] and takes a number of hours equal to the item''s encumbrance, or a minimum of one hour. If the check is successful, the device is broken down into a number of components equal to its encumbrance plus 1."},{"key":null,"count":1,"misc_desc":"Characters can try to use component alteration to physically disguise these individual parts to look like code cylinders, comlinks, fusion lanterns, and other mundane objects. While this allows a part to take on the rough appearance of the desired object, it does not gain the functionality of that object. This is generally a taxing and tricky process, and so upgrades the difficulty of the Mechanics check once or more as per the GM''s discretion."},{"key":null,"count":1,"misc_desc":"Each [SU] or [TR] on the initial Mechanics check lets a character carrying the components from a component alteration add [BO] to [B]opposed Stealth vs. Perception checks[b] when an observer attempts to notice the true nature of the disassembled device. If the component alteration was designed to make the items appear mundane, he gains [BO][BO] instead."},{"key":null,"count":1,"misc_desc":"Assembling a weapon or other item with a component alteration requires two maneuvers or two minutes of narrative time per component, and the character must make an [B]Average ([DI][DI]) Mechanics check[b]. All components must be present to make the check. Failure means the components are damaged and the device requires a major repair to be properly reassembled again and returned to function."},{"key":null,"count":1,"misc_desc":"The GM may spend [TH][TH][TH] as [DE] when a character makes a skill check while using an item with this alteration."},{"key":null,"count":1,"misc_desc":"A character can only attempt a component alteration once on a given item, and doing so permanently reduces the item''s available hard points by 1. Items that have no hard points may still be altered in this fashion."}]'::jsonb, NULL, NULL),
  ('COMPONENT', 'Componentization', 'Componentization This mod allows a weapon to be broken down into a number of innocuous-looking pieces so that it can be smuggled into and out of places where weapons are not allowed or are highly regulated. When broken down, a componentized weapon looks like a collection of basic tools, comlinks, glow rods, datapad styluses, and other items any individual might be expected to carry. Each part also functions as that item as well. It takes two maneuvers to assemble or disassemble a weapon with this mod. Loss of or damage to a component ruins the weapon, and another will have to be acquired and modified. This attachment can be applied to any weapon with an encumbrance of 2 or less. Models Include: Various models.', 'Weapon', 2, 1250, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Allows a weapon to be broken into pieces and disguised as other items. A character must make a [B]Formidable ([DI][DI][DI][DI][DI]) Mechanics[b] or [B]Skulduggery check[b] to deduce the items are weapon parts."}]'::jsonb, NULL, NULL),
  ('CONCEALALTERWEAP', 'Concealment Alteration (Weapon)', 'Concealment Alteration (Weapon) Holdout blasters and vibroknives are easy enough to hide, but when characters wish to pack a bit more of a punch, they need a more powerful (and usually larger) weapon. The simplest way to make a more obvious weapon or other item easier to conceal is to remove unnecessary parts or minimize its size. This is called a concealment alteration. Concealment alterations can include cutting weapon barrels, removing panels, and any other small physical changes that do not prohibit the item''''s primary function. PCs wishing to make a concealment alteration need to make an Average () Skulduggery check and spend one hour per point of the item''''s encumbrance (with a minimum duration of one hour) in applying the changes. A successful check reduces the item''''s encumbrance by 1 (to a minimum of 1) and adds to any Perception checks to notice or search for the item; can be spent to make this instead. Items with an encumbrance of 3 or higher are more difficult to modify, however, and so the difficulty to perform a concealment alteration increases by one for each point of encumbrance over 2. This means that making a concealment alteration to a typical ion blaster (encumbrance 3) would require a Hard () Skulduggery check, while doing so to a standard disruptor rifle (encumbrance 5) would require a Formidable () Skulduggery check. Items with an encumbrance of 6 or higher cannot receive a concealment alteration. A character can only attempt a concealment alteration once on a given item, and doing so permanently reduces the item''''s available hard points by 1. Items that have no hard points may still be altered in this fashion.', 'Weapon', 0, NULL, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"PCs wishing to make a concealment alteration need to make an [B]Average ([DI][DI]) Skulduggery check[b] and spend one hour per point of the item''s encumbrance (with a minimum duration of one hour) in applying the changes. Items with an encumbrance of 3 or higher are more difficult to modify, however, and so the difficulty to perform a concealment alteration increases by one for each point of encumbrance over 2. Items with an encumbrance of 6 or higher cannot receive a concealment alteration."},{"key":null,"count":1,"misc_desc":"A successful check reduces the item''s encumbrance by 1 (to a minimum of 1) and adds [SE] to any Perception checks to notice or search for the item; [TR] can be spent to make this [SE][SE] instead."},{"key":null,"count":1,"misc_desc":"A character can only attempt a concealment alteration once on a given item, and doing so permanently reduces the item''s available hard points by 1. Items that have no hard points may still be altered in this fashion."}]'::jsonb, NULL, NULL),
  ('CORRUPTCRYS', 'Corrupted Crystal', 'Corrupted Crystal Even the best of the Jedi can fall. The Empire scours the galaxy looking for the Force sensitives to enfold in the dark side. Untutored pupils wander far from the light, lost on dark paths from which they may never return. Many of them have either found or constructed lightsabers of their own with such crystals as they could and, in the course of their fall or their time astray, have committed heinous acts suffused with the dark side of the Force. They bend the kyber crystals in their lightsabers to their will, leading to the bloody red hue or are redeemed, they leave behind a weapon and a crystal strongly associated with the dark side of the Force. These crystals must be purged of their evil to avoid letting them fall into other hands and corrupt them as well. Thus, a Force user may take on the task of reclaiming these crystals. A corrupted crystal is a lightsaber crystal.', 'Weapon', 2, NULL, 9, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"VICIOUS","count":2,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When character wielding this lightsaber makes a Force check, add [DA] to the check"},{"key":null,"count":1,"misc_desc":"When wielder''s Morality rises to 70 or more, [DA] is no longer added to Force checks, and the crystal loses the Vicious quality"}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null},{"key":"SUBQUALVICIOUS","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('CRACKEDCRYS', 'Cracked Crystal', 'Cracked Crystal With the destruction of the Jedi, the Empire has begun to horde kyber crystals for itself, capturing and controlling traditional sources of the crystals in order to develop strange new weapons. Force users must look for non-traditional sources of lightsaber crystals wherever they may be found, regardless of their condition. For example, with the destruction of the Death Star, a new, if difficult to access, source of crystals has been revealed. At the heart of the great battle stations lay a giant kyber crystal powering the lasers that destroyed Alderaan. When the Alliance destroyed Alderaan. When the Alliance destroyed the Death Star, the crystal shattered in the resulting explosion and scattered itself across the open space of the Yavin system. Most of the shards are unusable, either too small or too damaged to function, and many of them succumbed to the gravity wells of the planets of the Yavin system. However, some few remain, quietly circling among the remaining debris fields, cracked and unstable, but functional. Special lightsaber modifications are needed to use such crystals properly, but to the willing Force user, they can be made into distinctive blades. A cracked crystal is a lightsaber crystal.', 'Weapon', 2, NULL, 10, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":2,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"If a combat check results in a [DE], GM may cause crystal to shatter."}]'::jsonb, '[{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"VICIOUS","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('JEDHACR', 'Cracked Jedha Crystal', 'Cracked Jedha Crystal When a terrible mining accident destroyed Jedha City, the galaxy lost one of the last known sources of kyber crystals. The crystals produced on Jedha held great spiritual significance for the Jedi, the Church of the Force, and a number of other religious traditions. Jedha crystals were among the most popular kyber crystals for the Jedi. As a practical matter, Jedha crystals produce focused, potent lightsaber blades, but many Jedi valued the knowledge that their lightsaber housed an artifact from Jedha. For those who seek to follow in the Jedi''''s path, kyber crystals have become vanishingly rare in recent years. However, a small number of Jedha crystals have been recovered from the ruins of Jedha City. Unfortunately, many of these crystals are cracked and damaged, producing unstable, ragged lightsaber beams. Models Include: None.', 'Weapon', 3, 8000, 7, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"INACCURATE","count":2,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, '[{"key":"VICIOUS","count":3,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null},{"key":"SUBQUALINACCURATE","count":1,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('CURVEDHILT', 'Curved Hilt', 'Curved Hilt The curved hilt is preferred by duelists and practitioners of the lightsaber combat form Makashi. This modification allows for both better control and better flexibility when handling the lightsaber. and for more force behind overhand strikes. Models Include: None.', 'Weapon', 1, 1000, 6, ARRAY['Lightsaber']::text[], '[{"key":null,"count":1,"misc_desc":"Adds automatic [ADVANTAGE] to successful Lightsaber combat checks when engaged with a single opponent."}]'::jsonb, '[{"key":"DEFENSIVE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('CUSTGRIP', 'Custom Grip', 'Custom Grip A skilled tinkerer can tailor a weapon to perfectly fit its wielder''''s hand. A custom grip is crafted to uniquely match its owner, allowing the weapon to act as an extension of the wielder''''s body. While the weapon fits perfectly in the hands of its owner, others who try to use it find the grip uncomfortable or the weapon off-balance. A finely customized grip is the hallmark of a master weaponsmith. This attachment can be applied to any weapon with a handle. Models Include: None', 'Weapon', 1, 500, 6, ARRAY['Pistol','Rifle','Carbine','Blaster','Bowcaster','Lightsaber','Lightsaber Hilt','Cutting Edge Melee','Bludgeoning Melee','Powered Melee','Shield','Portable Gunnery']::text[], '[{"key":"SETBACKSUB","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Anyone other than owner adds [SE][SE] to combat checks using this weapon."}]'::jsonb, '[{"key":"ACCURATE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('CUSTOMFIT', 'Custom Fit', 'Custom Fit Although standard "off-the-shelf" armor can provide invaluable protection, it can also prove bulky or awkward, even after adjustments. For those who require their armor to feel like a second skin, personalized customization can make a drastic difference. Such work requires a skilled armorer, but it can make body armor a much more enticing option for some. This attachment can be applied to any armor. Models Include: Numerous variants', 'Armor', 1, 400, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Removes [SE] from Athletics and Stealth checks."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Remove an additional [SE] from Athletics and Stealth checks"}]'::jsonb, NULL),
  ('CW', 'Cortosis Weave', 'Cortosis Weave Although uncommon and even considered archaic in this day and age, some armorers specially equip protective gear with an underlying weave of rare cortosis. This does tend to make the armor more resistant to being penetrated (especially by energy weapons), but the cost is seldom worth the result. Models Include: Numerous variants.', 'Armor', 2, 10000, 8, NULL, '[{"key":"CORTOSIS","count":null,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('DAMPEMIT', 'Damping Emitter', 'Damping Emitter Careful modifications to the power cells and blade emitter allow the owner of a lightsaber to add a stun setting of sorts, drawing on the power of a normal lightsaber crystal, but with less intensity than is normally used. A damped lightsaber can still inflict serious injuries, however, as the emitter can only limit the power of a heavily modified crystal so much. Models Include: None; users must custom make each lightsaber attachment.', 'Weapon', 1, 2000, 7, NULL, '[{"key":null,"count":1,"misc_desc":"As a maneuver, may adjust lightsaber to deal Stun damage.  Decrease damage by 2, increase critical rating by 1, lose Breach quality"}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Stun Damage +1"}]'::jsonb, NULL),
  ('DANTARI', 'Dantari Crystal', 'Dantari Crystal As their name suggests, Dantari crystals are found on the Outer Rim world of Dantooine. Discovered within the eggs of the kinrath—giant, venomous, cave-dwelling arachnids—it is unknown how Dantari crystals come into existence. However, these multihued kyber crystals were once extremely popular among the Jedi. When installed in a lightsaber, a Force-reactive Dantan crystal helps the wielder maintain focus and calm. A Dantari crystal is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 12000, 9, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When making a Force power check as part of a combat check, may spend [FORCEPOINT] to recover 2 strain."}]'::jsonb, '[{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('DRAGITE', 'Dragite Gem', 'Dragite Gem Small, dull, and brittle, Dragite gems are found in the caves and caverns of the D''''olop mountain range on M''''haeli, an agriworld in the Expansion Region. In their natural state, dragite crystals are one of the most brittle kyber crystals, and they produce a loud ringing when struck. Worked into a suitable lightsaber crystal, a difficult task due to the dragite gem''''s distressing tendency to fracture or shatter easily, it produces a blade that pulses and hums loudly. In addition to this noise, when a lightsaber equipped with a dragite gem strikes a solid target, it produces a deafening crack and a shock wave that can disorient and even cause bodily harm to its target. A dragite gem is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 14000, 7, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"DISORIENT","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null}]'::jsonb, '[{"key":"DISORIENT","count":2,"misc_desc":null},{"key":"CONCUSSIVE","count":2,"misc_desc":null},{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('DROIDBRAINDEF', 'Droid Brain Defense System', 'Droid Brain Defense System An extremely unusual upgrade generally reserved for powered armor suits, a droid brain defense system uses a full sensor suite to alert wearers to and help them avoid threats. The most basic models simply warn the user of threats and indicate ideal cover positions through a haptic interface or by voice. More advanced models incorporate a system of complex motors or even repulsor generators throughout the armor to literally throw the wearer out of the way of incoming fire. These droids often develop highly paranoid personalities, and their earnest attempts to protect their master even outside of combat can prove highly inconvenient.', 'Armor', 3, 5000, 6, NULL, '[{"key":"DEFADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Increase Defense by 1 when taking Guarded Stance maneuver."}]'::jsonb, NULL),
  ('DROIDBRAINDETON', 'Droid Brain Detonator', 'Droid Brain Detonator Weapons manufacturers, combat engineers, and sabotage specialists are constantly inventing new triggers and detonators for explosive devices of all kinds, in order to provide for every conceivable situation. One of the most sophisticated and uncommon triggers makes use of an actual droid brain. Whereas timers, proximity detectors, and other common detonators are all effective within their narrow parameters, a droid brain is adaptable for nearly any situation or plan. A droid brain is able to abide by extremely specific trigger conditions and to follow complex instructions. For instance, users might instruct a detonite charge to wait thirty minutes after several specific individuals have entered a facility before igniting, or tell their frag grenade to avenge them should they fall in battle. Droid brain detonators are intensely loyal, even by droid standards, but they tend to develop distinct personality quirks over their relatively short existences. Some are annoyingly chipper and enthusiastic, perhaps owing to additional layers of obedience programming, while others exhibit anything from childlike naivete to nihilistic moroseness. This attachment can be applied to any grenade or explosive device.', 'Weapon', 0, 1000, 4, ARRAY['Explosive','Grenade']::text[], '[{"key":null,"count":1,"misc_desc":"Explosive''s detonator is controlled by a droid brain that can activate under any predetermined circumstance."}]'::jsonb, NULL, NULL),
  ('DROIDTARGET', 'Droid Targeting System', 'Droid Targeting System Although droids are most commonly thought of as autonomous mobile constructs, the advanced artificial intelligence of droid brains has been used in a variety of other applications for thousands of years. A specialized droid mind equipped with sensors and miniaturized gyromotors can improve the accuracy of even the most experienced sentient marksman. Many soldiers look down on the use of such systems, while others find the vibrations as the droid subtly adjusts their aim to be frustrating, to say the least. Droid targeting systems are known for their often bossy and impatient personalities. This attachment can be applied to any personal ranged weapon.', 'Weapon', 3, 3200, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Upgrade ability on Ranged combat checks made with this weapon once."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add [BO] to one Ranged combat check per encounter"},{"key":null,"count":1,"misc_desc":"Suffer 3 strain to remove [DE] from Ranged combat check"}]'::jsonb, NULL),
  ('DUALPHASE', 'Dual-Phase Modification', 'Dual-Phase Modification Considered antiquated and outdated by the time of the Clone Wars, the dual-phase modification is an artifact of an older, more violent time. Designed to catch an opponent off guard, this modification allows the wielder to change the length of a lightsaber''''s blade with the push of a button. This causes an opponent''''s guard to falter momentarily as he adjusts to the new blade length, allowing the Jedi to press the advantage while his opponent is confused. Models Include: None.', 'Weapon', 2, 4500, 6, ARRAY['Lightsaber']::text[], '[{"key":null,"count":1,"misc_desc":"May change blade length once per encounter as an incidental.  Next attack that turn ignores target''s melee defense."}]'::jsonb, NULL, NULL),
  ('ELECSIGHTSYS', 'Electronic Sighting System', 'Electronic Sighting System By adding a small electronic device to the top of a blaster or other ranged weapon, a small holographic crosshair is projected a meter out from the weapon’s barrel. This increases accuracy by reducing the time it takes for the user to aim. Unfortunately, the holographic crosshair is readily visible to anyone on the weapon’s receiving end, especially in conditions of darkness or low light. This attachment can be used on any ranged weapon that could logically benefit from the addition of a sight.', 'Weapon', 1, 500, 4, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Allows shooter to aim as an incidental once per round at short range.  Decreases the difficulty of Perception checks to locate the shooter in low light conditions by 1."}]'::jsonb, '[{"key":"ACCURATE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('ENERDISP', 'Energy Dispersion System', 'Energy Dispersion System This minute metallic wiring is designed to distribute electrical shocks across the armor while grounding the user against the energy, reducing the potency of such attacks. It protects against electricity as well as weapons'''' Stun settings, although it does not effectively disperse blaster fire. This attachment can be installed on any armor. Models Include: Atlas Corp Model 88 Electric Shield, Merr-Sonn AEGIS Nanoarray.', 'Armor', 1, 500, 4, NULL, '[{"key":null,"count":1,"misc_desc":"When reducing strain damage by soak, count soak as two higher"}]'::jsonb, NULL, NULL),
  ('ENVADAPTKIT', 'Environmental Adaption Kit', 'Environmental Adaption Kit The varied and often hazardous environments found throughout the galaxy have a tendency to hinder and harm even the sturdiest, most well-built pieces of equipment. Ranged weapons, especially energy weapons like blasters, are particularly susceptible to environmental damage. Dirt, dust and sand can scratch fog lenses, reducing a blaster beam''''s cohesion and therefore its range and damage potential. Moisture can collect in barrels and receivers, corroding galven circuitry or rusting bolts and strikers. More exotic environments can wear away at weapons with heat, caustic gases, or damaging ionization. To combat these dangers, most weapon and weapon accessory manufacturers produce Environmental adaptation kits. Primarily just collections of seals and protective covers, these kits grant a weapon an added layer of protection against the wear and tear of regular use in hostile environments. While some are for general use, most of these kits are designed for specific environments: dusty, cold, caustic, etc. Environmental adaptation kits can be attached to any ranged weapon. Models Include: Various models and manufacturers. Note: If this kit is for a specific environment, rename the kit to specify the environment.', 'Weapon', 1, 100, 2, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Prevents a weapon from breaking down as a result of a specific type of environment."}]'::jsonb, NULL, NULL),
  ('ENXCITER', 'Enhanced XCiter', 'Enhanced XCiter Outlaw Techs have long known how to modify the gas conversion enabler in a blaster to yield a more highly energetic—and correspondingly more destructive—payload. Such modified XCiter modules are highly unstable, however, and are sometimes disparaged as being just as dangerous to the wielder and anyone else nearby as to the enemy. Despite the risk and the illegality of the modification, many outlaws seek out such customizations to gain an edge in a firefight. This attachment can be applied to any blaster.', 'Weapon', 2, 1500, 6, ARRAY['Blaster']::text[], '[{"key":"CRITSUB","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"GM may spend [DE][DE] to cause blaster to explode, destroying blaster and inflicting automatic Critical Injury on wielder."}]'::jsonb, '[{"key":"PIERCE","count":3,"misc_desc":null}]'::jsonb, NULL),
  ('EODMKIIDATALINK', 'Data Link', 'Data Link EOD-Mk II Upgrade Options: EOD-MK II suits lack any standard modification options, but can be upgraded with two valuable attachments. These attachments are integrated load-bearing gear and a data link for controlling EOD and demolitions remotes, such as the EOD-Mk IV. As the suits are designed for these upgrades, neither takes up any hard points for the armor, but each upgrade can only be taken once. The data link allows the wearer to control a single EOD remote and costs an extra 300 credits with a rarity of 4.', 'Armor', 0, 300, 4, NULL, '[{"key":null,"count":3,"misc_desc":"Allows wearer to control a single EOD remote."}]'::jsonb, NULL, NULL),
  ('EODMKIILOAD', 'Integrated Load-Bearing Gear', 'Integrated Load-Bearing Gear EOD-Mk II Upgrade Options: EOD-MK II suits lack any standard modification options, but can be upgraded with two valuable attachments. These attachments are integrated load-bearing gear and a data link for controlling EOD and demolitions remotes, such as the EOD-Mk IV. As the suits are designed for these upgrades, neither takes up any hard points for the armor, but each upgrade can only be taken once. Integrated load-bearing gear reduces the suit''''s encumbrance by 3, and costs an additional 700 credits with a rarity of 3.', 'Armor', 0, 700, 3, NULL, '[{"key":"ENCSUB","count":3,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('EOS', 'Enhanced Optics Suite', 'Enhanced Optics Suite Built into a helmet, this system provides an individual with a host of specialized optical and audio sensors. Each system is equipped with passive light amplification, thermal signature readers, ultrasound pickups, millimeter wave emitters, video capture, and common optical enhancements. This may be installed on any armor. Models Include: BioTech MULTI Enhanced Vision System, Atlas Corp Full-Spectrum Optical Enhancer, Neuro-Saav Anq-Y Enhanced Optics Suite.', 'Armor', 1, 1000, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Removes up to [SETBACK][SETBACK] added to all Perception,\r\n          Vigilance, and combat skill checks\r\n          due to darkness, smoke, or other environmental effects\r\n          that obscure vision."}]'::jsonb, '[{"key":"VIGIL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('EOVERSET', 'Energy Overclock Setting', 'Energy Overclock Setting As deadly and dangerous as they are, vibroweapons can be even deadlier with the inclusion of an overclock setting. By replacing several internal components with precision analogs, a qualified technician can exponentially increase the speed and frequency of a vibroblade''''s blade action. The result is a vibroweapon that can be charged for amplified cutting power, but at the expense of causing unpredictable power fluctuations. This attachment can be applied to any vibroweapon and any other powered Melee or Brawl weapon.', 'Weapon', 3, 500, 5, ARRAY['Powered Brawl','Powered Melee']::text[], '[{"key":null,"count":1,"misc_desc":"Once per turn, spend a maneuver to add Vicious +3 to weapon until end of round.  [TH][TH][TH] or [DE] causes weapon to cease functioning until end of encounter."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add automatic [AD] to combat checks with this weapon"},{"key":null,"count":1,"misc_desc":"Activate as an incidental instead of a maneuver"}]'::jsonb, NULL),
  ('ETAAN', 'Etaan Crystal', 'Etaan Crystal These unusual kyber crystals from in the deep caverns of the Mid Rim world of Etai. Given that the crystals rarely form fewer than five hundred meters below the surface and usually at over twice the depth, the formation can be extremely difficult to locate. However, the raw crystals echo any nearby sound with a humming resonance, guiding searchers who draw near. Harvested etaan crystals retain this resonant property causing the activated blades of lightsabers using them to thrum in harmony with the motion of the blade, and to chime at nearby sounds. The blades respond especially spectacularly to a clash with another lightsaber or blaster bolt, emitting a near-deafening crack and a bright flare of energies. A clash of blades involving etaan crystals usually results in the lightsabers being forced apart, but reflected blasted bolts draw in the resonant energies from the reaction and intensify on their new trajectory.', 'Weapon', 1, 12000, 9, NULL, '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"If wielder uses the Improved Reflect talent to inflict an automatic hit, increase damage by 2."}]'::jsonb, '[{"key":"VICIOUS","count":1,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"PARRY","count":1,"misc_desc":null},{"key":"REFLECT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('EXTHILT', 'Extended Hilt', 'Extended Hilt The idea behind the extended hilt modification is to increase the lightsaber''''s striking i4 and cutting power by using the leverage of the longer handle and a two-handed grip to help focus the wielder''''s strength into the force of the blow. The extended hilt modification is also popular among Force users of unusual height or build as a way to capitalize on their size advantage in combat. Models Include: None.', 'Weapon', 1, 3800, 7, ARRAY['Lightsaber']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('FAG', 'Forearm Grip', 'Forearm Grip Little more than a vertical handgrip affixed below the barrel of a rifle-sized weapon, forearm grips are a popular modification among mercenaries, designed to give the user better control over the weapon. This Attachment can only be used on rifles (but not heavy rifles) and carbines. Models Include: Galactic Arms Model 94 Forearm Grip, Dolmax 14A Detachable Pistol Grip, Merr-Sonn AG44S Ergonomic Tactical Foregrip.', 'Weapon', 1, 250, 1, ARRAY['Rifle','Carbine']::text[], '[{"key":null,"count":1,"misc_desc":"Decreases the additional difficulty of making Ranged (Heavy)\r\n          checks with this weapon while engaged to an\r\n          additional [DIFFICULTY] (rather than [DIFFICULTY][DIFFICULTY])."}]'::jsonb, '[{"key":"POINTBL","count":1,"misc_desc":null},{"key":"ACCURATE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('FFS', 'Filed Front Sight', 'Filed Front Sight An old assassin''''s trick, this is the simple act of removing the front sight of a blaster pistol by filing it off. A common modification to holdout blasters (along with removing their serial numbers), filing down the weapon''''s front sight allows it to be drawn more quickly from its holster, and reduces the possibility of it becoming snared on clothing. Unfortunately, while this modification makes for easy concealment and drawing, it also reduces the weapon''''s accuracy, as it effectively makes it impossible to aim with any amount of precision. This modification may only be applied to pistol-sized weapons. Applying it oneself requires an Average () Mechanics check; the cost is paying others to perform the modification. Models Include: None.', 'Weapon', 1, 25, NULL, ARRAY['Pistol']::text[], '[{"key":null,"count":1,"misc_desc":"Increases the difficulty of combat checks to hit targets at\r\n          ranges beyond Short range by one."},{"key":"QUICKDR","count":null,"misc_desc":null}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Decreases the difficulty of checks to conceal the weapon by one."}]'::jsonb, NULL),
  ('FLICKERPHASE', 'Flickerphase Blade', 'Flickerphase Blade Considered dishonorable and unsporting by most Jedi, so-called flickerphase modifications were never widely adopted. With a few simple modifications, a lightsaber can be made to intermittently and randomly ignite and extinguish its blade, making it appear to fIicker on and off. While this unpredictable element adds some difficulty for the wielder, it is almost impossible for an opponent to time blocks and parries effectively. Models Include: None.', 'Weapon', 1, 5000, 4, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSUB","count":2,"misc_desc":null},{"key":"INACCURATE","count":2,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When attacking with this lightsaber, targets cannot use the Parry incidental to reduce the damage of the attack"}]'::jsonb, '[{"key":"SUBQUALINACCURATE","count":1,"misc_desc":null},{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('FORRESON', 'Force-Attuned Resonator', 'Force-Attuned Resonator When the Jedi artificer Sokiro Terebin set about reproducing the crystalline, force-attuned resonators from the blasters she had unearthed at Site-145 on Filata, she first had to solve some numerous technical challenges. During this time, she created a number of internal resonators that could be housed within a weapon the effectiveness of different technologies the ancients might have used. Though she meticulously recorded all of her efforts to create resonators that could be activated only by Force sensitives, the Empire''''s tumultuous rise to power led the destruction of many repositories of Jedi lore. During Terebin''''s lifetime, few Jedi considered these weapons to be serious armaments, but in the dark times of Imperial rule, some Force sensitives might find having a blaster that most people can''''t operate to be practical. The blueprints persist in certain scholastic records, and the aspiring Force sensitives might be able to make a use of them. This attachment can be applied to any Ranged (Light) or Ranged (Heavy) weapon that has a trigger.', 'Weapon', 1, 1000, 8, ARRAY['Pistol','Rifle','Carbine','Heavy Rifle','Heavy Carbine']::text[], '[{"key":null,"count":1,"misc_desc":"Must possess Force Rating 1+ to operate this weapon."}]'::jsonb, '[{"key":"PRESSHOT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('GALPATRES', 'Galven Pattern Resequencing', 'Galven Pattern Resequencing Some Alliance operatives would gladly trade a little reliability in exchange for the stopping power necessary to penetrate Imperial armor. This makes the Galven pattern resequencing a popular upgrade among troops in service of the Rebellion. By focusing the Galven pattern into a tighter wavelength, more energy is packed into each blaster bolt, which increases damage output. Unfortunately, the added workload on the blaster’s tiny circuitry makes the weapon much more prone to failure. This attachment can only be used with blaster pistols and heavy blaster pistols.', 'Weapon', 2, 1000, 5, ARRAY['Blaster Pistol','Heavy Blaster Pistol']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"THRADD","count":2,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"PIERCE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('GENELOCK', 'Gene Lock', 'Gene Lock Some sentients form a great attachment, even a bond with their weapon, and take steps to ensure that no other can use it. For this, or for more practical reasons, some individuals have their weapon modified so that it only functions in their hands. This is accomplished through a gene-lock: a system- featuring a computer that, once loaded with the user''''s genetic code, samples and scans the DNA of any individual who picks up the weapon. If his genetic profile does not match the weapon''''s designated user, the computer locks down the weapon and prevents it from firing. This upgrade is most relevant for ranged weapons, but it is possible to gene-lock a vibroblade or similar weapon. In this case, an unauthorized user can still wield the weapon as a basic sword, etc., but any technological components such as a vibro-motor cease to function. This attachment can be applied to any handheld weapon.', 'Weapon', 1, 500, 7, NULL, '[{"key":null,"count":1,"misc_desc":"Weapon functions only in the hands of its authorized user."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Self-Destruct.  Inflicts one critical hit if unauthorized user tries to use locked weapon.  Weapon is destroyed."}]'::jsonb, NULL),
  ('GHOSTFIRE', 'Ghostfire Crystal', 'Ghostfire Crystal These kyber crystals grow in nearly invisible formations on a handful of far flung Outer Rim worlds. Their precarious spires of entirely transparent stones rise from rocky foundations. They are typically found at the peaks of mountains, when they can be located at all. Finders can use ghostfire crystals to construct a lightsaber with a blade as difficult to detect as the spire from which they harvested the crystal. Lightsabers with ghostfire crystals at their core produce no sound whatsoever, and the blades are dim and translucent compared to the incandescent fire of the other lightsabers. most curious of all are the illusory afterimages of the blades that follow the wielders'''' motions, disorienting foes and disguising the true position of their blades.', 'Weapon', 1, 14000, 9, NULL, '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Wielder may spend [AD][AD][AD][AD] or [TR] to prevent the target from using the Parry talent to reduce damage from this attack."}]'::jsonb, '[{"key":"DEFENSIVE","count":2,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('GRAPNEL', 'Under-Barrel Grapnel Launcher', 'Under-Barrel Grapnel Launcher Often seen among mercenary and special operations forces, an under-barrel grapnel launcher provides a quick way to scale sheer surfaces in the midst of a combat situation or during a covert infiltration. A durasteel hook, possibly with a mono-molecular point, can find purchase on nearly any surface, while a spool of synthrope or liquid cable provides up to 100 meters of length. A powerful motor automatically retracts the cable, pulling the user up - though holding onto any passengers who are along for the ride is a more difficult matter, and requires some effort on part of the user. This attachment can be used with any Ranged (Light) or Ranged (Heavy) weapons that could logically have a grapnel launcher mounted on it. Models Include: Merr-Sonn KR-2 Auxiliary Grapnel, TaggeCo "Skysailer" Grapnel Launcher', 'Weapon', 2, 500, 3, NULL, '[{"key":null,"count":1,"misc_desc":"As an action, may make an [B]Average ([DI][DI]) Ranged (Light) check[b] to secure grappling hook to an object within medium range and reel in cord."},{"key":null,"count":1,"misc_desc":"May pull another character aloft by making an [B]Average ([DI][DI]) Athletics check[b]."}]'::jsonb, NULL, NULL),
  ('GRENCLING', 'Grenade Cling', 'Grenade Cling While some anti-vehicle explosive devices and some concussion grenades are equipped with an electromagnetic clamp as a standard feature, such capabilities are rare among anti-personnel grenades. With the addition of an electromagnet, adhesive polymer, plastoid webbing, or any of a dozen other measures, nearly any grenade or bomb can be made to latch onto its target, preventing escape and ensuring its destruction. The attachment can be added to any grenade or explosive device.', 'Weapon', 0, 70, 2, ARRAY['Explosive','Grenade']::text[], '[{"key":null,"count":1,"misc_desc":"Grenade immediately adheres to its target and requires an [B]Average ([DI][DI]) Athletics check[b] to remove."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Increase damage by 1 to stuck targets"},{"key":null,"count":2,"misc_desc":"Increase difficulty to remove adhered grenade once"}]'::jsonb, NULL),
  ('GYROSTAB', 'Gyrostabilizer', 'Gyrostabilizer A gyrostabilizer, or repulsorlift harness, artificially reduces the weight of the weapon, allowing a user to heft and aim a heavy weapon with decreased difficulty. With such a modification, a single combatant can operate a weapon that normally requires a team of two. These sophisticated devices are comparatively expensive and rare, and thus are seldom seen outside of elite forces. This attachment can be applied to any Ranged (Heavy) or Gunnery Weapon. Models Include: TaggeCo Type 2 Repulsorlift Harness, BlasTech Mk. IV Gyrostabilization Unit', 'Weapon', 2, 1000, 6, NULL, '[{"key":"SUBQUALCUMBERSOME","count":1,"misc_desc":null}]'::jsonb, '[{"key":"SUBQUALCUMBERSOME","count":3,"misc_desc":null},{"key":"BAR","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('HANDSFREEWEAP', 'VX Hands-Free Weapon', 'VX Hands-Free Weapon By modifying his armor to mount one or more weapons, a spacer can keep his hands free for whatever unexpected needs might arise in combat—or just to carry more weapons. While few weapons are intended for such use, most can be modified to mount on a properly-equipped suit of armor. The difficult part is modifying the weapon so that it can be aimed and fired hands-free. Methods range from voice-activation to a pressure-sensitive glove activated by certain hand movements to a direct neural link. Such systems almost always incorporate a sophisticated targeting computer or retinal tracking mechanism. The most common location for the weapon mount is on the shoulder, though other areas are possible. A weapon must also be modified in order to be armor-mounted, requiring one hard point. This attachment can mount any Ranged (Light) or Ranged (Heavy) weapon with an Encumbrance of 4 or less, subject to the GM''''s discretion.', 'Armor', 2, 1000, 6, NULL, '[{"key":"MOUNTRANGED4","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"User can aim and fire mounted weapon without using hands."}]'::jsonb, NULL, NULL),
  ('HARDENED', 'Hardened', 'Hardened Power armor relies on its energy source to maintain functionality. If this flow of energy is interrupted by a powerful electromagnetic burst or exposure to ion weapons, the armor loses both its mobility and its ability to enhance the wearer. With the armor''''s vital systems "hardened" against such effects, power armor becomes immune to these attacks. Such hardening modifications are weighty, however. Adjustments must be made to nearly every subsystem to prevent even partial shutdowns from taking place. This attachment can only be applied to power armor.', 'Armor', 2, 900, 4, ARRAY['Powered']::text[], '[{"key":null,"count":1,"misc_desc":"Prevents deactivation of power armor by electromagnetic or ion weapons."}]'::jsonb, NULL, NULL),
  ('HEAT', 'Heating System', 'Heating System Like thermal shielding, cold shielding is installed in armor to protect the wearer against dangerously low temperatures and frigid environments. Equipped with small, efficient heating elements and double-insulated against the cold, this attachment allows a wearer to survive in places where the ambient temperature can be dozens of degrees below freezing. Perhaps the most famous type of cold shielding is that built into the custom laminate armor worn by the Imperial Army''''s snowtroopers. This attachment can be installed on any armor that covers the entire body and can be sealed. Models Include: Atlas Corp DL87 "Frostback" Armor Enhancement, Min-Dal Model 00 Heating System.', 'Armor', 1, 1000, 3, ARRAY['Sealed']::text[], '[{"key":null,"count":1,"misc_desc":"Reduces the difficulty of Resilience checks made\r\n          to resist the effects extreme cold by one.\r\n          Removes up to [SETBACK][SETBACK] added to checks\r\n          due to extreme cold."}]'::jsonb, NULL, NULL),
  ('HELMETCOM', 'Helmet Comlink', 'Helmet Comlink Rather than rely on a separate piece of equipment that can be broken, lost, or stolen, some mercenaries and bounty hunters prefer to install a micro comlink directly into their armor. A micro-comlink can comprise anything from a complete in-helmet system to a simple small microphone and speaker attached to a wristplate or near the shoulder. A micro-comlink can be installed in any armor.', 'Armor', 0, 200, 1, NULL, '[{"key":null,"count":1,"misc_desc":"A long-range comlink is integrated into the helmet"}]'::jsonb, NULL, NULL),
  ('HELMETSCAN', 'In-Helmet Scanner', 'In-Helmet Scanner An in-helmet scanner provides the usefulness of a general purpose scanner in a heads-up display splashed across the inside of the users helmet. This feeds the user a constant stream of information about the surrounding environment. Depending on the specific model, an in-helmet scanner can indicate the presence of life forms or droids and display heat signatures, radiation sources, acoustic emissions, and more. Many can also scan and listen to nearby comlink frequencies. In-helmet scanners can be added to any helmet. Models Include: CryonCorp GoScan, CUE Optical Information System (Mobile), Chedak Mk. 7 HUD-INFO.', 'Armor', 1, 750, 4, NULL, '[{"key":null,"count":1,"misc_desc":"Adds a general purpose scanner\r\n          to the user’s helmet. The scanner allows the user to\r\n          remove [SETBACK] imposed on any checks due to darkness\r\n          or environmental conditions such as smoke or fog. It\r\n          also allows the user to detect heat sources and motion\r\n          within medium range."}]'::jsonb, NULL, NULL),
  ('HIDCOMPARMOR', 'Hidden Compartments in Armor', 'Hidden Compartments in Armor Usually formed from rigid plates or packed with protective padding, most types of armor rarely facilitate the stowing of small objects. However, with some careful work, a character can add hidden pouches, concealed holsters, and unseen sheaths. A character typically shaves down or hollows out a section of armor plating, or thins out protective mesh and padding, to make space for the hidden compartment. To make this change, he must spend a number of hours equal to the armor''''s encumbrance, pay a number of credits equal to 5% of the armor''''s price, and make a Hard () Mechanics check. Each or provides one encumbrance point''''s worth of hidden space in the armor. The armor cannot gain more encumbrance points for hiding objects than the suit''''s own encumbrance value, and items concealed in this way do not count towards the user''''s encumbrance threshold. Add to all Perception checks made to notice items hidden in this manner. No matter how many are rolled, though, a suit of armor cannot conceal any single item with an encumbrance value greater than 2. This means that if a character rolls and thus has space for items totaling 3 encumbrance, the character could conceal a heavy blaster pistol (encumbrance 2) and a vibroknife (encumbrance 1), but not a blaster carbine (encumbrance 3). This is because while it is possible to hollow out a compartment in a chest plate and perhaps a second in a boot, there is no single location on a suit of armor large enough to accommodate a particularly large or unwieldy item. Each point of encumbrance value for concealed space gained in this fashion reduces the armor''''s hard points by one, to a minimum of 0. Any armor with no hard points, such as padded armor or heavy clothing, can still have enough concealed space for an item with an encumbrance value of 1. For every two encumbrance points'''' worth of concealed space created, an armor''''s soak is reduced by one. However, each net on the initial Mechanics check to modify the armor cancels out one point of soak reduction.', 'Armor', 0, NULL, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"[B]Price:[b] 5% of armor''s price."},{"key":null,"count":1,"misc_desc":"To make this change, he must spend a number of hours equal to the armor''s encumbrance and make a [B]Hard ([DI][DI][DI]) Mechanics check[b]. Each [SU] or [TR] provides one encumbrance point''s worth of hidden space in the armor. The armor cannot gain more encumbrance points for hiding objects than the suit''s own encumbrance value, and items concealed in this way do not count towards the user''s encumbrance threshold. Add [SE][SE] to all Perception checks made to notice items hidden in this manner."},{"key":null,"count":1,"misc_desc":"No matter how many [SU] are rolled, though, a suit of armor cannot conceal any single item with an encumbrance value greater than 2."},{"key":null,"count":1,"misc_desc":"Each point of encumbrance value for concealed space gained in this fashion reduces the armor''s hard points by one, to a minimum of 0. Any armor with no hard points, such as padded armor or heavy clothing, can still have enough concealed space for an item with an encumbrance value of 1."},{"key":null,"count":1,"misc_desc":"For every two encumbrance points'' worth of concealed space created, an armor''s soak is reduced by one. However, each net [AD] on the initial Mechanics check to modify the armor cancels out one point of soak reduction."}]'::jsonb, NULL, NULL),
  ('HILTMASK', 'Hilt Masking Kit', 'Hilt Masking Kit Often, openly carrying a lightsaber causes undue comment and notice. Owners of such a weapon may have many reasons to want a subtler presence, yet still keep their lightsaber by their side. Perhaps they must enter an area known to be under heavy Imperial scrutiny, or the mere presence of an obvious weapon may sour delicate negotiations. Whatever the reason, Force users may make use of a hilt-masking kit to disguise their weapon. Just as each lightsaber is unique to its user, so too is each hilt-masking kit; there is no "universal" kit. The needs of the moment, or the personal tastes of the Force user, dictate what form each kit takes. Sometimes a hilt may be disguised as a cane; at other time it could be hidden as a part of a more mundane weapon like a blaster rifle; it may even appear to be something much more ordinary, like a pair of microbinoculars. The cost, rarity, and encumbrance of a hilt-masking kit are the same as that of the item it is meant to look like. Whatever form the masking takes, it provides two important qualities: it looks as little like a lightsaber as possible, and it provides quick and easy access to the full weapon when needed.', 'Weapon', 1, NULL, NULL, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":null,"count":1,"misc_desc":"Adds [FA][FA] to any attempt to find or identify the lightsaber as a lightsaber."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Increase number of [FA] by 1"}]'::jsonb, NULL),
  ('HUNTBARREL', 'Hunting Barrel', 'Hunting Barrel Designed to increase range and accuracy, a hunting barrel can turn any blaster rifle into a dedicated hunting weapon. This two-meter-long replacement barrel is constructed of lightweight materials and packed with upgraded pulse adapters and denser, more aggressive galven circuitry. The increased accuracy and range come at the cost of the base weapon''''s weight and size, however. The extra-long barrel makes the weapon awkward to handle and fire without proper support, as well as making it almost impossible to conceal. A hunting barrel can only be used on a blaster rifle. Models Include: Czerka Model 2 "Huntsman" Precision Barrel, SoroSuub WQ60 "Sure-shot" Barrel, Arakyd 3100 "Deadeye" Barrel.', 'Weapon', 3, 1200, 4, ARRAY['Blaster Rifle']::text[], '[{"key":"RANGEADD","count":1,"misc_desc":null},{"key":"CUMBERSOME","count":2,"misc_desc":null},{"key":"ENCADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"ACCURATE","count":2,"misc_desc":null},{"key":"LETHALBL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('ILUM', 'Ilum Crystal', 'Ilum Crystal The kyber crystals found deep within the caves of the icy planet Hum were prized by the Jedi as some of the best crystals for constructing a lightsaber. Ilum featured heavily in Jedi tradition, with young Padawans traveling there as part of their training to commune with the Force and use its guidance to seek out the crystal that would go into the construction of their first lightsaber. Models Include: None.', 'Weapon', 2, 9000, 10, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null}]'::jsonb, '[{"key":"VICIOUS","count":2,"misc_desc":null},{"key":"DAMADD","count":4,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('INTASCGEAR', 'Integrated Ascension Gear', 'Integrated Ascension Gear Incorporating a grapnel launcher, line, clips and other climbing and rappelling equipment directly into a set of armor ensures that the user is always prepared to ascend or descend sheer surfaces in a hurry. Whether to escape from pursuers, follow a target, infiltrate a secure building or exfiltrate from a dangerous situation, ascension gear can prove invaluable in a variety of situations. In addition, having the grapnel and line integrated directly into one''''s armor provides a high degree of safety and security. This attachment can be applied to any armor. Models Include: TaggeCo Integrated Ascension Unit, VargeCorp ClimbAll Armor.', 'Armor', 2, 350, 3, NULL, '[{"key":null,"count":1,"misc_desc":"As an action, may make an [B]Average ([DI][DI]) Ranged (Light) check[b] to secure grappling hook to an object within medium range and reel in cord."},{"key":null,"count":1,"misc_desc":"May pull another character aloft by making an [B]Easy ([DI]) Athletics check[b]."}]'::jsonb, NULL, NULL),
  ('INTHOLST', 'Integrated Holsters', 'Integrated Holsters By mounting their holsters into the framework of their armor, combatants can ensure no one can catch them unarmed. Not only does the wearer have easy access to these weapons at all times, but powered servos an other systems can be set up to assist the wearer in drawing or stowing these weapons more rapidly. A character with a fully tooled set of integrated holsters has access to a hidden arsenal that can overwhelm most foes. Models Include: BlasTech "Personal Armory" Gear.', 'Armor', 2, 300, 4, NULL, '[{"key":"HOLSTER3","count":2,"misc_desc":null}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Add [SE] to Perception checks to find stored weapons"},{"key":"HOLSTER3","count":3,"misc_desc":null},{"key":"QUICKDR","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('INTILL', 'Integrated Illuminator', 'Integrated Illuminator Operating in darkness is never ideal, but there are several ways to compensate for one''''s lack of night vision. The simplest, perhaps, is to integrate a simple spotlight, similar in most respects to a high-power glow rod, along the length of a ranged weapon''''s barrel. In addition to providing illumination in dark conditions, high-powered spotlights have the potential to blind enemies. This attachment can be applied to any ranged weapon that could logically benefit from a spotlight.', 'Weapon', 1, 200, 4, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Removes up to [SE][SE] due to darkness on targets within short range."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Increase spotlight range to medium"},{"key":"DISORIENT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('INTMEDSYS', 'SmartMed 2000 Integrated Med-Systems', 'SmartMed 2000 Integrated Med-Systems For some, it is not enough for their armor to simply prevent injury—it must lessen the effects of those wounds they do suffer. Integrated med-systems range from automated stim-injectors to sophisticated medical computers and full-body bacta baths. Though they can never replace a doctor or medical droid, these med-systems can keep the user alive long enough to get proper treatment, or to continue fighting despite his wounds. This attachment can be added to any armor that covers the majority of the wearer''''s body, subject to the GM''''s discretion.', 'Armor', 2, 2500, 7, ARRAY['Full Body','Half Body']::text[], '[{"key":null,"count":1,"misc_desc":"Once per session, may apply stimpack as incidental."},{"key":null,"count":1,"misc_desc":"All Medicine checks made to heal wearer gain [BOOST]."},{"key":"ENCADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"HEALPLUSONE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('INTSCAN', 'OmniScan 3 Integrated Scanner', 'OmniScan 3 Integrated Scanner Warriors must be aware of their surroundings at all times, and ready to respond to any threat. Because a hand-held scanner both requires the user to direct his attention to it and restricts his weapon use, it is common for military forces to integrate scanner systems into helmets. As usual, many Hired Guns follow suit, particularly those with a military background. Most integrated scanner systems utilize a heads-up display, projected on the inside of the helmet''''s visor. Some systems include a retractable mono-visor that extends only while the scanner is in use.', 'Armor', 1, 1000, 4, NULL, '[{"key":null,"count":1,"misc_desc":"Built-in general purpose scanner"},{"key":null,"count":1,"misc_desc":"Adds [BOOST] to Perception checks to detect movement or hidden enemies."}]'::jsonb, '[{"key":"PERC","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('INTSCAN2', 'Integrated Scanner', 'Integrated Scanner A scanner incorporated into a weapon allows the user to keep a rifle readied while constantly monitoring the surrounding area for danger. Specialized units might detect life signs, movement, or the energy cells of weapons. The battlefield awareness added by such a device can make the difference between victory and defeat. This attachment can be applied to any Ranged (Heavy) weapon. Models Include: Carbanti United Electronics Mk. II Omni-Scope, CryonCorp "Heads-Up" Scanner Suite', 'Weapon', 2, 675, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Weapon incorporates a general-purpose scanner."},{"key":null,"count":1,"misc_desc":"Wielder adds automatic [AD][AD] to Initiative checks while weapon is drawn."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Remove [SE] from Initiative checks"}]'::jsonb, NULL),
  ('INTSLICGEAR', 'Integrated Slicer Gear', 'Integrated Slicer Gear Slicers must often conduct their work under strict time constraints and less than ideal conditions. By integrating a customized computer, dataports and gesture interface circuitry into worn armour, a slicer can ensure that the tools of the trade are always at hand and almost impossible to lose. A visor-mounted heads-up display or holographic image streams the data the slicer needs, while specially designed gloves or gauntlets allow the slicer to manipulate code using nothing more than gestures and brief voice commands. This attachment can be applied to any armor. Models Include: MerenData Mobile XR-1, numerous custom variants', 'Armor', 3, 750, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Counts as having Slicer Gear.  Can be controlled by gesture or voice."}]'::jsonb, '[{"key":"TECHAPT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('IONBLAST', 'Secondary Ion Blaster', 'Secondary Ion Blaster A secondary ion blaster provides an extra level of offense for those expecting run-ins with droids. Many Technicians prefer to take enemy droids intact, the better to "recruit" them or even scavenge for parts later. An ion blaster mounted alongside another weapon provides just that option. This attachment can be used with any Ranged (Heavy) weapon. Models Include: SoroSuub Droid Defender, BlasTech Model 9 Under-Barrel Ion Blaster', 'Weapon', 2, 400, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Adds an ion blaster to the weapon."},{"key":"CUMBERSOME","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('IONSHIELD', 'Ion Shielding', 'Ion Shielding Rarely encountered in body armor and more commonly (and usually illegally) applied directly to droid chassis, ion shielding provides protection against ionization blasters. Although the mitigation it grants is far from complete, the energy-dampening effects can keep a droid operational where it would otherwise be shutdown. This attachment can be applied to any armor with soak 2 or higher. Models Include: Outlaw Tech Ion Shielding, Industrial Automaton Mk. III Ion Guard', 'Armor', 1, 2000, 7, NULL, '[{"key":null,"count":1,"misc_desc":"Increase soak by 3 against weapons with Ion quality."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Increase ranged and melee defense by 1 against weapons with Ion quality"}]'::jsonb, NULL),
  ('IONTHRUSTSHAPEDNOZ', 'Shaped Nozzle', 'Shaped Nozzle By adding a metal cone to an ion thruster, a Technician can dramatically increase its potency as a weapon, focusing the energy into a sharp beam rather than letting it disperse in a wide arc.', 'Weapon', 0, 75, 1, NULL, '[{"key":"REMQUALION","count":1,"misc_desc":null}]'::jsonb, '[{"key":"PIERCE","count":5,"misc_desc":null}]'::jsonb, NULL),
  ('JUMPBOOTS', 'Jump Boots', 'Jump Boots Jump boots are, essentially, a single-use jetpack built into a thick boots and allows a user to leap over tall obstacles and even fly for a very limited time. This attachment can be applied to any armor with an encumbrance of 4 or less. It is good for only one use and cannot be used again until the rockets are refueled, which costs 100 credits and takes 30 minutes. Models Include: Zim Systems LO-44.a micro-rockets.', 'Armor', 1, 1200, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Reduce difficulty of all Athletics checks to jump up or over obstacles by 1"}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Reduce difficulty of all Athletics checks to jump up or over obstacles by 1"},{"key":null,"count":1,"misc_desc":"Allow wearer to fly for a total of one minute or 3 rounds"}]'::jsonb, NULL),
  ('JURYRIGGEDA', 'Jury Rigged (Armor)', 'Jury Rigged (Armor) The character chooses one personal weapon or piece of armor per rank of Jury Rigged. He may increase the damage of the weapon by one; decrease the Advantage cost on its Critical, or any single other effect by one to a minimum of one; or increase armor''''s ranged or melee defense by one. Alternatively, he can decrease the encumbrance of the item by two to a minimum of one. The bonus only applies so long as the character is using the item. If the item is ever loss or destroyed, the character may apply Jury Rigged to a new personal weapon or piece or armor.', 'Armor', 0, NULL, NULL, NULL, NULL, '[{"key":"MELEEDEFADD","count":1,"misc_desc":null},{"key":"RANGEDEFADD","count":1,"misc_desc":null},{"key":"ENCSUB2","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('JURYRIGGEDW', 'Jury Rigged (Weapon)', 'Jury Rigged (Weapon) The character chooses one personal weapon or piece of armor per rank of Jury Rigged. He may increase the damage of the weapon by one; decrease the Advantage cost on its Critical, or any single other effect by one to a minimum of one; or increase armor''''s ranged or melee defense by one. Alternatively, he can decrease the encumbrance of the item by two to a minimum of one. The bonus only applies so long as the character is using the item. If the item is ever loss or destroyed, the character may apply Jury Rigged to a new personal weapon or piece or armor.', 'Weapon', 0, NULL, NULL, NULL, NULL, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"ENCSUB2","count":1,"misc_desc":null},{"key":"QUALADVSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('KIIRCOAT', 'Kiirium Coating', 'Kiirium Coating An obselete shielding material once processed in abundance in the Si''''klaata Cluster, kiirium was at one time vital to the manufacture of heavy weapons and starships. While largely supplanted by cheaper, more durable alloys, kiirium has properties that make it useful to armorsmiths, who can apply a coating of kiirium to armored plating as a relatively effective thermal shielding. This attachment can only be applied to armor that has hard or solid parts around which the allow can be coated, such as with laminate armor, heavy battle armor, and similar types of armor at the GM''''s discretion.', 'Armor', 2, 2500, 7, ARRAY['Hard','Hard Full Body']::text[], '[{"key":null,"count":1,"misc_desc":"+1 soak vs. blaster and flame attacks"}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Decrease the difficulty of Resilience checks made to resist the effects of fire and extreme heat by 1"}]'::jsonb, NULL),
  ('KIMBER', 'Kimber Stone', 'Kimber Stone Kimber stones are a type of kyber crystal produced by violent volcanic activity on the moon of Y''''ness in the N''''zoth system. They were once considered unsuitable for use in lightsabers due to the non-lethal nature of the blades they create. Certain Jedi Knights saw potential in kimber stones, and so a number were acquired from Y''''ness prior to the destruction of the Jedi Order. Today, kimber stones are occasionally sold at auction on the black market, usually as mere trinkets by those who do not understand their true value as kyber crystals. A kimber stone is a lightsaber crystal.', 'Weapon', 2, 6500, 8, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":9,"misc_desc":null},{"key":"CRITSET","count":null,"misc_desc":null},{"key":"STUNDAMAGE","count":null,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null},{"key":"CONCUSSIVE","count":1,"misc_desc":null},{"key":"DISORIENT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('KRAYT', 'Krayt Dragon Pearl', 'Krayt Dragon Pearl Highly sought after by jewelers, artisans, and wealthy collectors for their luster, color, and refractive properties, krayt dragon pearls are perhaps the rarest of the crystals used in the construction of lightsabers. The terrible krayt dragons of Tatooine tend to live for an incredibly long time, and over the course of their lives will ingest stones to aid with digestion. While the caustic digestive juices of the krayt dragon can even break down stone over time, every once in a while these stones contain some form of kyber crystal. Incredibly resilient, they remain in the creatures'''' guts for the entirety of the dragons'''' lives, slowly being polished and smoothed into small, dense spheres of crystal. The resulting "krayt dragon pearls" are vanishingly rare, hard to acquire, and demand exorbitant prices. Since they are a type of kyber crystal, they can be worked into powerful lightsaber crystals—ones which produce an exceptionally savage and destructive blade that makes an unsettling howling noise when swung about. A krayt dragon pearl is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 15000, 10, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":9,"misc_desc":null},{"key":"CRITSET","count":1,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, '[{"key":"VICIOUS","count":3,"misc_desc":null},{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('LASERSIGHT', '"Bantha''s Eye" Laser Sight', '"Bantha''''s Eye" Laser Sight An extremely simple gun sight, a laser sight emits a low-power light beam to place a visible "dot" that marks the weapon''''s precise target. A laser sight can help even an amateur shooter hit a target. One drawback to this upgrade is that the laser can alert an otherwise unaware target to the shooter. For these reasons, laser sights are rarely used by sharpshooters and snipers. This attachment can be used with any Ranged (Light) or Ranged (Heavy) weapon that do not possess the Blast quality.', 'Weapon', 1, 500, 5, NULL, '[{"key":"ADVADD","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('LIGHTFR', 'Lightweight Frame', 'Lightweight Frame This mod reduces both the weight and bulk of ranged weapons to make them easier to handle and conceal. Along with a frame made of a lighter alloy, this mod also includes lightweight polycarbonate stocks, foregrips, and other pieces designed to lighten up a blaster pistol or slugthrower rifle. This attachment can be applied to any weapon. Models Include: BlasTech "Featherlite" blaster frame.', 'Weapon', 1, 650, 3, ARRAY['Ranged']::text[], '[{"key":"ENCSUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":"ENCSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('LORRDIAN', 'Lorrdian Gemstone', 'Lorrdian Gemstone Lorrdian gemstones arc kyber crystals mined millen nia ago by enslaved Lorrdians during the Kanz Disorders. Created by Force-sensitive Lorrdians to supplement the intricate kinetic communication developed among the slave populace, these gemstones were imbued with Force energies that allowed their possessors to read the emotions and actions of others. When installed in a lightsaber, a Lorrdian gemstone allows the wielder to predict the actions of an opponent, giving the wielder a decided edge in melee combat. A Lorrdian gemstone is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 9600, 8, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null}]'::jsonb, '[{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":"DEFLECTION","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('LOWFRIC', 'Low-Friction Coating', 'Low-Friction Coating Low-friction coatings work by lowering the coefficient of friction against solid armor plates. With the addition of such a coating, the surface of armor becomes almost impossible to grip or seize. In addition, glancing blows from melee weapons are often unable to find purchase, which diminishes the damage they cause as they slide off. The only downside to the coating is that is can make working on the armor more difficult, as tools must scramble for a grip on its slick surface. This attachment can only be applied to armor with hard surfaces such as heavy battle armor, powered armor.', 'Armor', 1, 750, 5, ARRAY['Hard','Hard Full Body']::text[], '[{"key":"MELEEDEFADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Add [SE][SE] to Mechanics checks to modify of maintain armor."}]'::jsonb, '[{"key":"COORD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('LTSABERCONST', 'Lightsaber Hilt Construction Modifications', 'Lightsaber Hilt Construction Modifications Use this attachment to reflect the results of a lightsaber hilt construction check, as required.', 'Weapon', 0, NULL, NULL, ARRAY['Lightsaber Hilt']::text[], NULL, '[{"key":"HPADD","count":4,"misc_desc":null},{"key":"HPSUB","count":4,"misc_desc":null},{"key":"ENCSUB","count":4,"misc_desc":null},{"key":"ENCADD","count":4,"misc_desc":null}]'::jsonb, NULL),
  ('M77TRANQ', 'SmartTranq', 'SmartTranq Developed in cooperation with CorChemCo, SmartTranq is an adaptable synthetic tranquilizer designed to be used with the Model 77 Air Rifle. When the tranquilizer enters the bloodstream of a target, it immediately begins to mutate, changing constantly and reconfiguring itself to find the quickest, most efficient way to overwhelm the target''''s defensive systems and render it unconscious. Upon a successful hit with the Model 77, the target must immediately make an Average () Resilience check. If the target fails, it suffers 5 strain, plus 2 additional strain per generated on the check. If the check generates , the GM can spend it to make the target check against the tranquilizer again during the next round. If the GM does so, increase the difficulty of the check by one. Equipping the Model 77 with SmartTranq costs 500 credits. This does not change the weapon''''s profile—it simply adds the above special rule to the weapon. If the weapon ever runs out of ammo, the user must purchase a reload (also costing 500 credits) before using the SmartTranq again.', 'Weapon', 0, 500, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"Upon hit, target must make [B]Average ([DIFFICULTY][DIFFICULTY]) Resilience check[b].  If fail, target takes 5 strain, plus 2 strain per [THREAT].  GM may use [DESPAIR] to make target check again next round at increased difficulty."}]'::jsonb, NULL, NULL),
  ('MAGTETH', 'Magnetic Weapon Tether', 'Magnetic Weapon Tether A magnetic weapon tether is a relatively simple modification that consists of a small magnetic device built into the weapon. The magnetic weapon tether allows the wielder to snap the weapon back to a readied position with a press of a button, rather than having to scramble to retrieve it. While many Force users might scoff at this ability - after all, why use a device for what they can do with the force anyway - others prefer to have the extra layer or safety, or wish to avoid using their Force powers openly in places where the Empire''''s presence is strong. This attachment can be applied to any weapon wielded in one hand that could logically benefit from a weapon tether.', 'Weapon', 1, 250, 2, NULL, '[{"key":null,"count":1,"misc_desc":"Wielder may recover engaged weapon as incidental."}]'::jsonb, '[{"key":"QUICKDR","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('MB', 'Marksman Barrel', 'Marksman Barrel Merr-Sonn''''s KX765 Marksman Barrel was designed to meet the needs of the finger for whom long-range accuracy is a necessity. Popular among bounty hunters and assassins, this barrel is nearly two meters long and made of lightweight materials. It features upgraded static pulse adapters as well as a denser galven circuitry pattern that not only increases the weapon''''s range, but also its accuracy. The trade-off for this increased range and accuracy is a weapon that''''s slightly awkward to use and nearly impossible to conceal due to the length of the barrel. This modification may only be applied to blaster rifles. Models Include: Merr-Sonn KX756 Marksman Barrel, SoroSuub WQ80 "Long-shot" Barrel, Arakyd 3300 Hawkeye Sharpshooter''''s Barrel.', 'Weapon', 2, 1200, 4, ARRAY['Blaster Rifle']::text[], '[{"key":"RANGEADD","count":1,"misc_desc":null},{"key":"CUMBERSOME","count":2,"misc_desc":null}]'::jsonb, '[{"key":"SNIPSHOT","count":1,"misc_desc":null},{"key":"ACCURATE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MEPHITE', 'Mephite Crystal', 'Mephite Crystal Mephite crystals are rare, lustrous kyber crystals found in a handful of places in and around the Adega system. One of five types of crystal known collectively as "Adegan crystals," mephite crystals are well-suited for use in lightsabers due to their internal structure and light-modulating capabilities. Like all Adegan crystals. mephite crystals are Force-reactive and can be infused with a small amount of a Force user''''s power. When installed in a lightsaber and infused with the Force, mephite crystals give off a small but steady Force signature that can be sensed by any nearby Force user A mephite crystal is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 10000, 10, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":8,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Force-sensitive characters using Force powers to sense their surroundings automatically detect a lightsaber using a mephite crystal if it is within the range of the power."}]'::jsonb, '[{"key":"DAMADD","count":3,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('MICROROCKARMMOUNT', 'Micro-Rocket Armor Mounting', 'Micro-Rocket Armor Mounting Micro-rockets are flexible (if dangerous) weapons favored as secondary arms by many bounty hunters (see Micro-Rockets on page 46), and generally fired from a mount installed in the wielder''''s armor. This attachment can be installed on any armor. Models Include: BlasTech Mag-Clip Micro-Rocket Mounting, Goseia HIC "Last Word" Launch/Targeter System, countless custom variants.', 'Armor', 2, 800, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Enables armor to fire loaded micro-rockets."}]'::jsonb, '[{"key":"LIMITEDAMMO","count":5,"misc_desc":null},{"key":"SETBACKSUB","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MICROROCKBOOST', 'Staged Rocket Booster', 'Staged Rocket Booster The limitations of size mean that most micro-rockets lack the fuel capacity to reach distant targets. However, high-yield fuel cells, advanced filtration systems, or staged boosters added to the rockets can all increase a rocket''''s effective range substantially. Of course, the term "effective range" becomes something of a misnomer with rockets modified in this way, as the additional fuel risks unbalancing the rocket''''s flight path, and the increased range comes with an increased chance of misjudgment on the part of the user. However, the chance to deliver a hefty payload beyond the reach of equivalent retribution is worth the risk to many. This attachment can be installed on any micro-rocket. Models Include: SoroSuub HV-33 Fuel Filter.', 'Weapon', 1, 25, 2, ARRAY['Micro-Rocket']::text[], '[{"key":"RANGEADD","count":1,"misc_desc":null},{"key":"INACCURATE","count":2,"misc_desc":null}]'::jsonb, '[{"key":"RANGEADD","count":1,"misc_desc":null},{"key":"SUBQUALINACCURATE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MICROROCKGUIDE', 'Rocket Guidance System', 'Rocket Guidance System Most micro-rockets are fired directly at their target, relying on the firer''''s aim and the rocket''''s acceleration to ensure a direct hit. For those who prefer more insurance that their rockets land precisely where intended, packages of sensors, limited fuel cell expansions, and adjustable maneuvering fins allow for rockets to be modified into maneuvering fins allow for rockets to be modified into "smart" weapons that continue to seek their designated target in the event of an initial miss or misfire. These systems enable users to get more reliable performance out of their rockets while at the same time minimizing the collateral damage. This attachment can be installed on any micro-rocket. Models Include: Phar Co. "Vornskr" Guidance Package, Merr-Sonn "Outreach" Target Sensor.', 'Weapon', 1, 50, 4, ARRAY['Micro-Rocket']::text[], '[{"key":"GUIDED","count":2,"misc_desc":null}]'::jsonb, '[{"key":"GUIDED","count":3,"misc_desc":null},{"key":"ACCURATE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MICROROCKRACK', 'Under-Barrel Micro-Rocket Rack', 'Under-Barrel Micro-Rocket Rack Micro-rockets can be fired in a plethora of ways, and some hunters mount them on their other weapons, giving these arms a deadly secondary fire mode (see Micro-Rockets on page 46). This attachment can be installed on any ranged weapon. Models Include: Blastech "Finisher" Rocket Rack, TaggeCo Under-Barrel Rocket Battery.', 'Weapon', 3, 1200, 6, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Enables weapon to fire loaded micro-rockets."},{"key":"CUMBERSOME","count":1,"misc_desc":null}]'::jsonb, '[{"key":"LIMITEDAMMO","count":2,"misc_desc":null},{"key":"SETBACKSUB","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MISSILESYS', '"Final Word" Secondary Missile System', '"Final Word" Secondary Missile System This uncommon attachment provides the user with the option for a single explosive attack, useful either as a last resort or as an opening salvo. The attachment holds a single rocket. This attachment can be used with any rifle that uses the Ranged (Heavy) skill.', 'Weapon', 3, 3000, 6, ARRAY['Rifle','Heavy Rifle']::text[], '[{"key":null,"count":1,"misc_desc":"Enables weapon to fire rockets, using missile''s profile."},{"key":"CUMBERSOME","count":2,"misc_desc":null},{"key":"ENCADD","count":3,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('MKTARGLOCK', 'Marked-Target Firing Lock', 'Marked-Target Firing Lock In the chaos of a firefight, shots can go astray, damaging property or bystanders. While some hunters do not care about the carnage they cause, this kind of haphazard damage is a liability, courting attention from the law or revenge from those who suffer in the crossfire. To mitigate this risk, some bounty hunters invest in firing locks on their blasters, allowing them to designate specific targets for the weapons. Once the systems'''' sensors have recognized a target, the weapons refuse to fire without a clear shot, minimizing the chance of collateral damage. This attachment can be installed on any ranged weapon that does not possess the Blast or Auto-fire quality. Models Include: BlasTech "Surefire" Safety Sensor, Cadregg Armory Model-87 Weapon Sensor.', 'Weapon', 1, 900, 4, ARRAY['Ranged']::text[], '[{"key":"THRCANCEL","count":1,"misc_desc":null}]'::jsonb, '[{"key":"THRCANCEL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('MME', 'Mono-Molecular Edge', 'Mono-Molecular Edge Even vibroweapons can benefit from an edge sharpened to molecular thickness and toughened through laser-forging techniques. This modification may be applied to melee weapons that use a cutting edge. Models Include: None listed.', 'Weapon', 1, 1000, 5, ARRAY['Cutting Edge Melee']::text[], '[{"key":"CRITSUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":"PIERCE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MOS', 'Multi-Optic Sight', 'Multi-Optic Sight A complex and sophisticated piece of equipment, the multi-optic sight is a wonder of modem sensor technology. Marketed to the discriminating professional soldier, each consists of a bulky on-weapon optic equipped with numerous sensors including low-light, thermal, ultrasound, millimeter wave emitters, video capture, and common optical enhancements. The optic is connected to a pair of goggles worn by the user by a reinforced fiber optic cable that transmits the vision enhancements directly to the user in real time. This allows the user to see around corners and over obstacles. This attachment can be fit to any ranged weapon. Models Include: Galactic Arms Model 44 Combat Optical Enhancer, SoroSuub XAD Omnisight, Merr-Sonn 480.z1 "Beholder" Multi-Optic Sight.', 'Weapon', 1, 2000, 3, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Removes up to [SETBACK][SETBACK]  on any checks\r\n          to use this weapon due to smoke, darkness, or other\r\n          environmental conditions that obstruct vision."}]'::jsonb, '[{"key":"PERC","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MOTTRACK', 'Motion Tracker', 'Motion Tracker The sophisticated device incorporates a full suite of onboard sensors and computers to track and predict the motion of a target, then feed that data back to the user through a variety of means, including a helmet HUD, a hardwired feed jacked directly into the brain, or other methods. The system might involve motive-actuators within the weapon to subtly adjust aim, or it might interface with motorized gloves. This attachment can be applied to any Ranged (Heavy) weapon. Models Include: CryonCorp Xv3 "Surefire" Motion Predictor, Industrial Automaton A-3 Tracking Computer.', 'Weapon', 2, 1000, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Remove [SE] due to target movement or use of Guarded Stance."}]'::jsonb, '[{"key":"PRECAIM","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('MULTICOMLINK', 'Multi-Band Comlink', 'Multi-Band Comlink It is common practice to incorporate a long-range comlink into a helmet. Many military or otherwise advanced helmets include a comlink as standard, and it is a fairly simple procedure to attach one to nearly any helmet. Some helmet comlinks are activated by tapping a button on the exterior of the helmet or somewhere else on the armor, while others are activated by voice or even a particular head motion.', 'Armor', 0, 200, 1, NULL, '[{"key":null,"count":1,"misc_desc":"A long range comlink is integrated into helmet."}]'::jsonb, NULL, NULL),
  ('MULTIGOOGASCART', 'Pressurized Gas Cartridge', 'Pressurized Gas Cartridge While a spray injector does not typically expel its contents with sufficient force to inflict serious harm, there is no particular reason it cannot do so if a tinkerer is willing to change out the factory-standard gas cartridge for one with a bit more kick. Needless to say, making such an alteration voids the multi-goo gun''''s warranty.', 'Weapon', 1, 100, 2, NULL, '[{"key":"DAMSET","count":5,"misc_desc":null}]'::jsonb, '[{"key":"BURN","count":2,"misc_desc":null},{"key":"DISORIENT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('NIGHTSCOPE', 'Night Vision Scope', 'Night Vision Scope This attachment uses an optical system similar to a set of electrobinoculars that shows infrared wavelengths of light, effectively allowing the shooter to track heat signatures in dark or concealed areas, or through walls. It does not differentiate between heat generated by life forms and other kinds of heat, whether from natural or manufactured phenomena. (It is blind to life forms that do not give off heat.) This attachment can be used on any ranged weapon, with the exception of single-use weapons and weapons that would not realistically benefit from a scope. Models Include: Fabritech LRS Low-Light Scope, Zikon Optics Model 45 Infrascope.', 'Weapon', 1, 700, 3, ARRAY['Ranged']::text[], '[{"key":null,"count":1,"misc_desc":"Remove up to [SETBACK][SETBACK] on any checks to use this weapon due to darkness"}]'::jsonb, NULL, NULL),
  ('NISHSTONE', 'Nishalorite Stone', 'Nishalorite Stone Nishalorite stones are found on worlds with particularly strong magnetic fields. Usually dark gray or blue-black in color, and possessing powerful magnetic properties, these stones are often used in electronics and magnetic navigation equipment. once properly cleaned and refined, they also make for excellent lightsaber crystals, as discovered generations ago by a wandering Jedi Seeker. While installed in a lightsaber, this stone creates a dense crackling blade with a subdued color that intensifies in the direction of a planet''''s magnetic north. It can detect natural and artificially generated magnetic fields such as those produced by generators of powerful electronic systems.', 'Weapon', 2, 12500, 8, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Add automatic [AD] to checks made to location position, navigate terrain, or find power sources or active technology."}]'::jsonb, '[{"key":"PLANMAP","count":1,"misc_desc":null},{"key":"DISORIENT","count":2,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('OCS', 'Optical Camouflage System', 'Optical Camouflage System Popular with both military scouts and assassins, optical camouflage systems are a wonder of modern stealth technology. Using a series of phased array optical projectors combined with sound baffling equipment and thermal and radiation shielding, Merr-Sonn''''s "Ghost" OCS can render a wearer nearly invisible to the naked eye. The PAO projectors allow the wearer to blend in with his surroundings by mimicking them, similar to an animal with active camouflage abilities, and the different radiation shields hide the wearers body heat as well as any electromagnetic radiation from other sensors or communications gear. For all of its utility, however, this system is incredibly fragile and is not recommended for combat. This attachment can be equipped on any type of armor, but is nearly useless on laminate and plastoid heavy armor, which is often too bulky and loud to mask properly. Models Include: BioTech "Flicker" Displacement Field, Atlas Corp "Smokescreen" Stealth System, Merr-Sonn "Ghost" Optical Camouflage System.', 'Armor', 2, 5500, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Upgrades the ability of all Stealth\r\n          checks twice while wearing this armor."}]'::jsonb, '[{"key":"MASSHAD","count":1,"misc_desc":null},{"key":"STEAL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('OPTENERGCELL', 'Optimized Energy Cell', 'Optimized Energy Cell An optimized energy cell or expanded gas reserve allows a blaster to achieve a much higher number of shots before needing to reload, thanks to more efficient use of resources. Such modifications are often the result of excessive tinkering, rather than off-the-shelf models. This attachment can be applied to any energy weapon. Models Include: Czerka Arms Model 4 Expanded Gas Reservoir, Blastech X-3 Extended Energy Cell', 'Weapon', 1, 100, 5, NULL, '[{"key":null,"count":1,"misc_desc":"When GM spends [DE] or [TH] to cause the weapon to run out of ammo, it requires an additional [TH]."}]'::jsonb, NULL, NULL),
  ('ORDIMPELL', 'Ordnance Impeller', 'Ordnance Impeller Over the millennia, tinkerers, weapon designers, and desperate fighters have come up with countless delivery systems for explosives, from missile tubes to combat droids. One less-popular approach that nonetheless endures among certain demolitions experts is the use of a modified grenade or detonite charge capable of self-propulsion. Such modifications are almost always unique, although certain small droids and other devices are a popular basis, despite manufacturer warnings. From a proton grenade with wheels to a hovering thermal detonator, these makeshift devices-when successful-allow unparalleled control of an explosive device from a considerable distance. This is generally achieved via a small holocam and remote-control unit, although the addition of a droid brain detonator can be exceedingly effective. This weapon attachment can be applied to any grenade or explosive device with an encumbrance value of 3 or less.', 'Weapon', 0, 500, 4, ARRAY['Explosive','Grenade']::text[], '[{"key":null,"count":1,"misc_desc":"Explosive can move overland at the rate of a character on foot."},{"key":null,"count":1,"misc_desc":"Includes a holocam and remote-control unit, allowing for movement and detonation from up to extreme range."},{"key":null,"count":1,"misc_desc":"Skill checks to operate device uses either Computers or Piloting (Planetary)."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add ten-meter maximum altitude."}]'::jsonb, NULL),
  ('OVERACTMOD', 'Overcharged Actuating Module', 'Overcharged Actuating Module An overcharged blaster actuating module provides for a more powerful shot at the cost of a greater use of gas as well as increased wear and tear on the weapon. For some spacers, these drawbacks are with the extra firepower. Although some kits are available for purchase many Technicians achieve the same result by scavenging parts from higher yield blaster. This attachment can be applied to any blaster pistol or carbine. Models Include: BlasTech Mk. II Actuating Module, SoroSuub BlastPro', 'Weapon', 1, 650, 7, ARRAY['Blaster Pistol','Blaster Carbine']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"GM may spend [TH][TH] to damage weapon by one step."}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('OVERPOWERCELL', 'Overcharged Power Cell', 'Overcharged Power Cell Lightsabers are exceptionally efficient weapons, able to run nearly forever off a single basic power cell, thanks to the remarkable focus of the kyber crystal installed within and the contained energy loop of the blade. As such, tampering with a lightsaber''''s power cell and adjusting its output usually does more harm than good, as it upsets the balance of a near-perfect system. Those who know what they are doing can sometimes overcharge the power cell of a lightsaber to increase the power of the blade, but these changes make the power cell volatile, prone to causing unpredictable fluctuations in the lightsaber''''s effects. When installed correctly, the effect of an overcharged power cell is more often beneficial than it is a hindrance, but the mere possibility of the blade dimming at the wrong moment dissuades some tinkerers from taking the risk. Models Include: None; users must custom make each lightsaber attachment.', 'Weapon', 1, 500, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Wielder can spend [AD] from combat checks to increase damage by 1.  GM can spend [TH][TH] to decrease damage by 1."}]'::jsonb, NULL, NULL),
  ('OVRCHARGEV', 'Overcharge Valve', 'Overcharge Valve An overcharge valve is a simple (if dangerous) modification that allows the wielder of a blaster to discharge the entire ammunition reserve in a single, devastating shot. This attachment can be applied to any blaster or energy weapon that could logically benefit from it. Models Include: Czerka "One-Shot" Overcharge Valve.', 'Weapon', 2, 1500, 6, NULL, '[{"key":null,"count":1,"misc_desc":"As incidental, weapon gains Prepare 1 quality and +4 damage for next attack.  After firing, weapon runs out of ammo."}]'::jsonb, NULL, NULL),
  ('PAIREDW', 'Paired Weapons', 'Paired Weapons Many Gunslingers wield a pistol in each hand, and some flashy pirates and other scoundrels even prefer to pair a blade with a pistol. This weapon modification balances a pair of weapons, allowing the wielder to use them in perfect tandem. This attachment can only be applied to one-handed weapons. Models Include: Custom variants.', 'Weapon', 1, 300, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Reduce [AD] required to hit with second weapon when two-weapon fighting by 1."}]'::jsonb, NULL, NULL),
  ('PASSFOLSUIT', 'Passive Foliage Suit', 'Passive Foliage Suit For those operating in the wilds, sometimes the simplest camouflage methods are the best. Given this, it''''s not surprising that hunters and other individuals who spend a lot of time in the wilderness often use passive foliage suits. These suits have patches of synthetic greenery designed to mimic natural flora. Clusters of open tie-lines also allow wearers to easily attach local foliage to the suit, allowing them to alter their camouflage when the surroundings change. This attachment can be applied to any armor that could logically integrate the necessary patches and tie-lines. Models Include: Various types.', 'Armor', 1, 75, 2, NULL, '[{"key":null,"count":null,"misc_desc":"Add [SE] to Perception or Vigilance checks made to detect a character wearing this armor in appropriate environment."}]'::jsonb, NULL, NULL),
  ('PISTOLGRIP', 'H9 Pistol Grip', 'H9 Pistol Grip A pistol grip replaces the stock or other grip on a long arm with one like that of a pistol, allowing it to be fired one-handed. Most blaster rifles feature a pistol-like grip by default, in which case this attachment makes additional modifications to make the weapon better-suited to one-handed use. This attachment can be used with any Ranged (Heavy) blaster rifle, blaster carbine, or slugthrower that does not possess the Cumbersome quality.', 'Weapon', 1, 400, 3, ARRAY['Rifle','Carbine']::text[], '[{"key":"USERANGLT","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Add [SETBACK] to any combat check made when firing one-handed."},{"key":"RANGEREDMED","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('PISTOLHILT', 'Pistol Hilt', 'Pistol Hilt While the Jedi of old disdained blasters, modern Force users often need every advantage they can get. By adding a customized secondary emitter to a lightsaber hilt, the wielder can release the energies of her weapon at a distance in a manner similar to that of a blaster bolt. Without the focused field produced by a regular lightsaber emitter, the beam rapidly loses coherency and stopping power, producing only a short-range stun bolt. A lightsaber used in this manner, though might not even be recognized for what it is, appearing to be an unusual or custom model of pistol instead of one of the legendary weapons of the Jedi. This additional layer of cover could mean as much protection as the new capabilities of the weapon. The user must spend a maneuver to switch from one weapon mode to the other lightsaber function to pistol function, for example. Models Include: None; users must custom make each lightsaber attachment.', 'Weapon', 2, 750, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Includes a built-in blaster pistol."}]'::jsonb, NULL, NULL),
  ('POISONRES', 'Poison Reservoir', 'Poison Reservoir Many assassins who use melee weapons choose to improve the lethality of their blades by adding a poison reservoir that releases a toxin through a channel in the blade at the push of a button in the hilt. While dipping a weapon in poison can be somewhat effective, a reservoir is a much more efficient delivery method. This attachment can only be used with Brawl and Melee weapons. Models Include: Numerous variants.', 'Weapon', 1, 400, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Allows user to store one dose of neurotoxin, anesthetic, neuroparalytic, or similar toxins."}]'::jsonb, '[{"key":"RESDOSE","count":4,"misc_desc":null}]'::jsonb, NULL),
  ('POMMELCAP', 'Pommel Cap', 'Pommel Cap Force users, especially those walking a path closely attuned to the light side of the Force, often seek non-lethal means for incapacitating their opponents. The pommel cap provides just such a solution. The pommel cap is a small, weighted knob or other similar piece attached to the base of a lightsaber''''s hilt. The increased weight and reinforcement provided by the pommel cap make pommel strikes with the lightsaber more effective, and less likely to damage the lightsaber itself, than a strike with a bare hilt. The pommel cap not only enhances the ability of a Force user to provide a stunning blow, but it can also be used to store small items of necessity-most often an additional backup power cell, though any number of small items can prove useful to a Force user in need. The pommel cap screws into the base of a lightsaber, and competent wielders often incorporate its use into their fighting style as a matter of course. This attachment can be applied to lightsabers or any Melee weapon with a hilt.', 'Weapon', 1, 3000, 2, ARRAY['Bludgeoning Melee','Cutting Edge Melee','Lightsaber','Lightsaber Hilt']::text[], '[{"key":"STUN","count":2,"misc_desc":null}]'::jsonb, '[{"key":"STUN","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('PROXDET', 'Proximity Detonator', 'Proximity Detonator Although certain models of mines include proximity detonators as standard, some desire this feature for grenades and other explosive devices. A proximity detonator adds an alternative trigger method: rather than detonating via a timer or on impact, the grenade only detonates when it detects the movement of a being or creature nearby. With the addition of a proximity detonator, a simple frag grenade becomes a deadly trap. A well-placed concussion grenade can incapacitate an entire squad of pursuing stormtroopers, giving Rebels better chances for escape. This weapon attachment can be applied to any grenade or explosive device.', 'Weapon', 0, 120, 3, ARRAY['Grenade','Explosive']::text[], '[{"key":null,"count":1,"misc_desc":"Weapon detonates when a silhouette 1 or higher creature comes within short or engaged range, as determined when placed."}]'::jsonb, NULL, NULL),
  ('QUICKSHED', 'Quick Shed', 'Quick Shed Armor, especially heavy armor, takes time to put on and take off. though putting armor on remains a chore, taking it off - especially in an emergency situation - is expedited with the quick shed attachment. By installing several quick-release latches at strategic locations, suits of armor can be quickly removed by the wearer. This attachment can only be applied to armor with an encumbrance of 3 or higher.', 'Armor', 1, 650, 4, NULL, '[{"key":null,"count":1,"misc_desc":"As a maneuver, wearer by shed the armor.  Armor must be reassembled before donning again, requiring several minutes and an [B]Average ([DI][DI]) Mechanics check[b]."}]'::jsonb, NULL, NULL),
  ('RADSHIELD', 'Radiation Shielding', 'Radiation Shielding The galaxy contains many perils, but one of the most common is radiation. From the depths of space to polluted industrial zones, radiation hazards both natural and artificial are a frequent threat to spacers. Although spacesuits provide a degree of protection and specialized hazard suits are available, some individuals prefer to also be protected from blaster bolts and blades. A variety of polymers, reflective coatings, and energy dampeners can be fitted or applied to armour to provide protection from radiation. This attachment can only be applied to laminate armor, heavy battle armor, and any other armor that can be fully sealed. Models Include: Loronar Model 4 Hostile Environment Treatment, Neuro-Saav Radiological Hazard Shielding.', 'Armor', 1, 500, 3, ARRAY['Sealable','Sealed']::text[], '[{"key":null,"count":1,"misc_desc":"Add [BO][BO] to Resilience checks to resist radiation."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Increase armor''s soak by 1 against damage caused by radiation"}]'::jsonb, NULL),
  ('RANGEFIND', 'MB-7 "Ranger" Range Finder', 'MB-7 "Ranger" Range Finder A system incorporating a simple computer and visual sensors, a range finder calculates the distance to any spot in the user''''s field of vision, feeding him precise information to a visor HUD. With this information, the wearer can push his weapon to its limits, while knowing when to hold his fire on an impossible shot. The most sophisticated systems interface directly with the user''''s weapon for increased effect.', 'Armor', 1, 1500, 6, NULL, '[{"key":"SNIPSHOT","count":1,"misc_desc":null}]'::jsonb, '[{"key":"SNIPSHOT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('RAPRECXC', 'Rapid-Recharge XCiter', 'Rapid-Recharge XCiter Specifically modified gas conversion enablers can allow a blaster pistol or rifle to achieve much higher rates of fire than those of a true repeating blaster. Along with modifying or replacing the XCiter, and potentially the blaster actuating module. Technicians making heavy modifications to a blaster also often modify the trigger to allow for fully automatic fire when the user keeps it depressed. Such high rates of fire mean a considerable loss in accuracy. Nevertheless, the advantages offered by a rapid-fire weapon outweigh these drawbacks for some users. This attachment can be applied to any blaster. Models Include: BlasTech XCelerator, SoroSuub M-3 Recycling Module, various custom models.', 'Weapon', 1, 750, 7, ARRAY['Blaster']::text[], '[{"key":"AUTOFIRE","count":null,"misc_desc":null},{"key":"INACCURATE","count":3,"misc_desc":null}]'::jsonb, '[{"key":"SUBQUALINACCURATE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('REACPLAT', 'Reactive Plating', 'Reactive Plating Reactive plating is a modification that attaches small explosive panels to the armors exterior plates. When hit by an attack, the explosives are designed to detonate outward, absorbing some of the attacks kinetic energy with the counter-explosion. It is not typically used on a personal scale, but microrepulsors and other, similar technologies allow it to be integrated into certain heavier varieties of personal armor and to function at considerable effectiveness without harming the wearer in the process. Employed properly, reactive armor can even deflect or dampen blows from weapons that would cleave through other defenses, like lightsabers. Besides the considerable weight it adds to any set of armor, an unfortunate side-effect of reactive armor is that it destroys itself as it protects the individual inside. It causes the armor to degrade far more rapidly than it would have otherwise would, which means that the wearer must repair it far more often. This attachment can only be applied to armor with a soak of 2 or higher.', 'Armor', 2, 2000, 6, NULL, '[{"key":null,"count":1,"misc_desc":"First time wearer is hit each encounter, reduce damage by 10.  After, armor suffers minor damage and must be repaired to function again."}]'::jsonb, '[{"key":"ENCSUB","count":3,"misc_desc":null}]'::jsonb, NULL),
  ('REFLADAPSKIN', 'Reflec Adaptive Skin', 'Reflec Adaptive Skin Reflec is an advanced polymer that possesses adaptive light-warping and sensor-damping properties. When applied to armor, reflec acts as an optical camouflage even in fully illuminated areas. This attachment can be applied to any armor. Models Include: CorChemCo Reflec Treatment.', 'Armor', 2, 3500, 7, NULL, '[{"key":null,"count":1,"misc_desc":"Upgrade ability of all Stealth checks once while wearing reflec-coated armor."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Add [BO] to Stealth checks while wearing reflec-coated armor"}]'::jsonb, NULL),
  ('REFLEXGRIP', 'Reflex Grip', 'Reflex Grip Through a delicate system of motion sensors and miniaturized motors built into a lightsaber hilt, a craftsperson can alter the lightsaber to respond to adjustments in grip and position with greater responsiveness. The split-second edge granted by this system allows a combatant to more easily parry an opponent''''s decisive stroke or block each of a hail of blaster bolts. Controlling the system and keeping it from overreacting to minute or inadvertent motions can be difficult to master, but the defensive advantage of a reflex grip can be worth the extra practice. Models Include: None; users must custom make each lightsaber attachment.', 'Weapon', 2, 4000, 8, NULL, '[{"key":null,"count":1,"misc_desc":"When lightsaber is used to Parry or Reflect, suffer 1 additional strain, but count Parry and Reflect ranks as 1 higher."}]'::jsonb, '[{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":"DEFLECTION","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('REFSHAD', 'Reflec Shadowskin', 'Reflec Shadowskin An advanced, light-absorbing polymer that can be applied to armor, reflec shadowskin coating can enhance the stealth abilities of its wearer - anyone wearing armor covered in this substance can easily blend into the shadows. While this coating does not make the wearer invisible, it does mean that observers who only catch a glimpse are far less likely to register what they saw or believe it to be anything more than a trick of the light. This attachment can only be applied to armor with a soak of 2 or lower.', 'Armor', 1, 1200, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Add automatic [AD] to Stealth checks"}]'::jsonb, '[{"key":"STALK","count":1,"misc_desc":null},{"key":null,"count":2,"misc_desc":"Add [SE] to Perception checks to see wearer"}]'::jsonb, NULL),
  ('REINFGAUNT', 'Reinforced Gauntlets', 'Reinforced Gauntlets Additional armor plating on the hands is a valuable upgrade for those who favor heavier armor, as well as those who do welding jobs on starships and desire to keep all of their fingers. Not only does such extra plating provide additional protection, but it ensures that the wearer is never unarmed; after all, the gauntlets are heavy enough to shatter bones when used to deliver a punch. It also helps protect the user''''s hands in case they are ever stuck closing a blast door or shocked by a loose wiring while performing battlefield repairs. This attachment can be applied to any armor with soak 2 or higher. Models Include: Various models', 'Armor', 2, 250, 2, NULL, '[{"key":null,"count":1,"misc_desc":"May use gauntlets as a melee weapon."}]'::jsonb, '[{"key":"DURA","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('REMAGSH', 'Reinforced Magnetic Shielding', 'Reinforced Magnetic Shielding A delicately tuned magnetic field maintains the coherency of a lightsaber''''s plasma beam. Though this modification increases the strength of a lightsaber''''s magnetic shielding, the blade takes on some of the qualities of a solid weapon. With this modification, the wielder gives up some of the lightsaber''''s legendary penetrative capacity in order to deliver punishing electromagnetic impacts. Models Include: None.', 'Weapon', 1, 4000, 5, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"REMQUALBREACH","count":null,"misc_desc":null},{"key":"CONCUSSIVE","count":1,"misc_desc":null},{"key":"KNOCKDOWN","count":null,"misc_desc":null},{"key":"PIERCE","count":1,"misc_desc":null}]'::jsonb, '[{"key":"CONCUSSIVE","count":1,"misc_desc":null},{"key":"DISORIENT","count":2,"misc_desc":null},{"key":"PIERCE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('REMSAFFEAT', 'Removed Safety Features', 'Removed Safety Features By removing or deactivating weapon safeties and other features a gun can more easily be drawn and readied for combat. Of course, these safety features are in place for a reason, and weapons modified in such a way tend to be more accident prone. This attachment can be applied to any Ranged (Light) or Ranged (Heavy) weapon that could logically have such elements to remove. Models Include: None', 'Weapon', 0, 250, 2, NULL, '[{"key":null,"count":1,"misc_desc":"Adds [BO] to first combat check during an encounter."},{"key":null,"count":1,"misc_desc":"GM may spend [TH][TH] to cause misfire.  Weapon runs out of ammo and inflicts 4 strain on wielder."}]'::jsonb, NULL, NULL),
  ('REPASSLIFT', 'Repulsor-Assisted Lifting', 'Repulsor-Assisted Lifting Although more common among factory or warehouse labor crews than in battle, repulsor-assist systems have gained some popularity among bounty hunters who need to haul in heavy catches. The systems operate through a series of miniaturized repulsorlift generators placed at key joints throughout the armor, easing the weight of attached suits, as well as any loads they might support. Of course, the repulsorlift generators are tuned to reduce weight and pressure rather than exert force on their own, so some hunters prefer powered armor suits with lesser lifting capabilities but more general applications for their servos. This attachment can only be used with laminate armor and other full-body hard armor suits. Models Include: Guldak Heavy Industries Personal Repulsor Fitting.', 'Armor', 2, 1000, 3, ARRAY['Hard Full Body']::text[], '[{"key":"ENCTBRADD","count":5,"misc_desc":null}]'::jsonb, '[{"key":"ENCTBRADD","count":2,"misc_desc":null},{"key":"ATHL","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('REPULSPACK', 'Repulsor Pack', 'Repulsor Pack While lacking the range and power of a true jetpack, a repulsor pack provides a reliable-and less terrifying-alternative for those new to the realm of personal flight devices. A repulsor pack allows for controlled descents from nearly any height, as well as hovering speeds of up to thirty-five kilometers per hour, its name being something of a misnomer, a repulsor pack actually consists of a number of small, relatively low-powered repulsor lifts mounted to the user''''s torso and limbs. Although the sight of an experienced user gliding through the air is quite impressive, the learning curve is steep. Perhaps due to the importance of leg movement in most packs for controlling movement and speed, the devices are sometimes disparagingly called "jet pants."', 'Armor', 2, 2500, 4, NULL, '[{"key":null,"count":1,"misc_desc":"Allows user to function as vehicle:  Speed 1, Handling -1, System Strain 2, Silhouette same as user."},{"key":null,"count":1,"misc_desc":"Pack can only travel in atmosphere up to 75 meters in altitude."},{"key":null,"count":1,"misc_desc":"Operator uses Coordination skill for any relevant checks."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Increase Handling by 1."}]'::jsonb, NULL),
  ('RIVETGUNBALBAR', 'Balanced Barrel', 'Balanced Barrel Adding a functional barrel to a rivet gun can give it dramatically more range and accuracy as a shooting weapon. Of course, such an addition also makes it obvious that the device is liable to be fired at range, as few Technicians can make a coherent case that they legitimately need to be able to bolt hull plates onto a ship with pinpoint accuracy at a distance of several meters.', 'Weapon', 1, 150, 3, NULL, '[{"key":"RANGEADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"SUBQUALINACCURATE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('RIVETGUNTOPLOAD', 'Top-Loading Magazine', 'Top-Loading Magazine By switching out the standard single-bolt loading system for a cobbled-together "magazine" containing numerous bolts, a skilled craftsperson can increase the number of rivets the gun can place per minute dramatically. Some use this to apply rivets more rapidly to other sentient beings, though all manufacturers consider this to be "user error".', 'Weapon', 1, 50, 1, NULL, '[{"key":"REMQUALLIMITEDAMMO","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('SACUST', 'Superior Armor Customization', 'Superior Armor Customization Any piece of armor can benefit from retooling at the hands of a superior craftsman. A skilled armorsmith can add improved plastoid or even durasteel plating to increase the protection a piece of armor offers even as he decreases its weight and bulk. Of course, such delicate and exacting work can make the armor less customizable in other respects. Models Include: Numerous Variants.', 'Armor', 1, 5000, 6, NULL, '[{"key":"SUPERIOR","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('SAPITH', 'Sapith Gem', 'Sapith Gem Said to originate from a strange and mysterious world called Lwhekk in the Unknown Regions, sapith gems are similar to krayt dragon pearls in that they were formed when rocks containing a kyber crystal were consumed by a great beast. In this case, the beast was a massive volice worm, which died out long before the present day. Thus, the only way to find these vanishingly rare crystals is to dig them out from the fossilized remains of a volice worm. Shaped like serpent scales, these smooth, lustrous crystals have an incredibly complex internal structure, which magnifies the intensity of any light that passes through them. When installed in a lightsaber, a sapith gem creates a powerful, intense beam that can pierce nearly anything with ease. A sapith gem is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 18000, 10, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null}]'::jsonb, '[{"key":"BREACH","count":1,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('SB', 'Spread Barrel', 'Spread Barrel Commonly applied to blaster rifles and carbines, BlasTech''''s "Scattergun" Spread Barrel is a common modification among spacers and fringers. Designed with close-quarters combat in mind, this attachment replaces a blaster''''s stock barrel with one shorter, bulkier, broader, and equipped with a built-in flash hider. Using a stepped array of prismatic crystals located at the end of the barrel as well as a reconfigured galven pattern, this barrel splits the blaster''''s beam into a number of smaller beams that exit the barrel in a spray pattern. Used in a tightly packed space, these beams can strike multiple targets with one pull of the trigger. The trade-off for this, however, is a reduction in the weapon''''s range. This attachment can only be applied to blaster rifles and blaster carbines. Models Include: BlasTech 8405 "Scattergun" Spread Barrel, SoroSuub 800 "Blunderbuss" barrel, Arakyd Model 70 "Chain Lightning" Spread Barrel.', 'Weapon', 2, 1725, 4, ARRAY['Blaster Rifle','Blaster Carbine']::text[], '[{"key":"RANGESUB","count":1,"misc_desc":null},{"key":"BLAST","count":4,"misc_desc":null}]'::jsonb, '[{"key":"BLAST","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('SCANPROOF', 'Scanner-Proof Hardware', 'Scanner-Proof Hardware Scanner-proof hardware is a collection of upgrades that together make a weapon virtually invisible to scanners. This mod typically replaces a weapon''''s stock, foregrip, and any other furniture with lightweight poly-carbonates woven with scanner-spoofing fibers. In addition, most if not all metallic parts—frame, trigger group, barrel, etc.—are replaced with fiber-reinforced polycarb pieces. This mod is extremely illegal. Being caught with a weapon that can pass through scanners without being detected is usually a one-way ticket to the nearest Imperial stockade. This attachment can be applied to any weapon. Models Include: Various models.', 'Weapon', 2, 1000, 6, NULL, '[{"key":null,"count":1,"misc_desc":"This weapon cannot be detected by standard weapon-detecting technologies. Characters using advanced scanners must make a [B]Hard ([DI][DI][DI]) Computers check[b] to find the weapon as usual."},{"key":null,"count":1,"misc_desc":"Game Masters may spend [TH][TH] or [DE] on a combat check to render the weapon inoperable, requiring a major repair before it can be used again."}]'::jsonb, '[{"key":"ENCSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('SCANWEAVE', 'Scannerweave', 'Scannerweave Scannerweave is a passive stealth system consisting of an advanced sensor-blocking textile. Armor modified with scannerweave tends to be quieter thanks to the nature of the soft, flexible fabric. More importantly, its inherent qualities make the wearer nearly invisible to the various scanners and security sensors found in security vaults and data facilities. This attachment can be applied to any armor. Models Include: Ayelixe/Krongbing Passive Stealth.', 'Armor', 2, 1800, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Upgrades the ability of all opposed Stealth checks made against sensor and scanner operators once."}]'::jsonb, NULL, NULL),
  ('SE', 'Serrated Edge', 'Serrated Edge The simplicity of this modification belies its viciousness. Adding a serrated edge to a weapon is something almost anyone can do, and giving a bladed weapon tearing edges ensures it does terrible damage to flesh and bone. This modification may be applied to melee weapons that use a cutting edge. Models Include: None.', 'Weapon', 1, 50, 1, ARRAY['Cutting Edge Melee']::text[], '[{"key":"VICIOUS","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('SEEKERCRYS', 'Seeker Crystal', 'Seeker Crystal No one seems to know where these crystals come from or how they make their way into the hands of their users. Rumors persist of markets so dark that none but a handful of beings know about them. Other rumors suggest that these crystals have an entirely different purpose and only incidentally happen to function as lightsaber crystals with unusual properties. Still others say they come from the deepest edges of the galaxy, from stars yet unknown. Whatever the case may be, those few that are known to exist have served their users well, allowing them to avoid ambush and surprise attack. Users of these crystals seem to instinctively know when they are being secretly observed or when their charges are in danger from hidden assassins. When ignited, blades produced by these crystals glow a soft pink color and connect users to the Force in such a way that they are able to detect those who hide nearby. While it is not a compass pointing the way to hidden beings, a wielder will know without a doubt that a concealed foe is near. A seeker crystal is a lightsaber crystal.', 'Weapon', 0, 16000, 9, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Force-sensitive wielders my add [AD][AD] to Perception or Vigilance checks to detect a hidden being within short range."}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Increase check range to medium"}]'::jsonb, NULL),
  ('SELFREPSYS', 'Self-Repair Systems', 'Self-Repair Systems Some sentients on the fringes of galactic civilization live a life of near-constant battle. For such individuals, a good suit of armor is vital, and keeping it in top condition is nearly as important. Some suits of armor include sophisticated self-repair suites, not dissimilar to the systems found in some droids. Smart materials, laminate extruders, electromagnetic assemblers and other systems work to keep the armor in one piece even under the greatest duress. This attachment can be applied to any armor with melee or ranged defense 1 or higher. Models Include: Industrial Automaton Model 3 Autorepair Suite, AccuTronics Advanced Repair Unit', 'Armor', 2, 3000, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Once per encounter as a maneuver, can have armor attempt to repair itself or assist in a repair.  Counts as Intellect 2 and Mechanics 2 ([PR][PR])."},{"key":null,"count":1,"misc_desc":"There is no cost to repair armor, whether using the automatic feature, or personally repairing."}]'::jsonb, NULL, NULL),
  ('SES', 'Strength Enhancing System', 'Strength Enhancing System Strength enhancing systems easily converts a suit of full armor into a power-assisted suit. Composed of a matrix of electrically controlled myomer synthetic muscle fibers backed up with nano-hydraulics, the MSES increases a wearer''''s raw physical strength, allowing him to lift more and carry more for longer periods of time. This attachment can only be used with laminate armor or similar full-body hard armor suits. Models Include: Industrial Automaton Xr5 Power Assist, BioTech "Brute Strength Enhancer, Atlas Corp Myomer Strength Enhancing System.', 'Armor', 2, 5500, 4, ARRAY['Hard Full Body']::text[], '[{"key":"BR","count":1,"misc_desc":null}]'::jsonb, '[{"key":"ATHL","count":2,"misc_desc":null},{"key":"BRA","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('SETTRIGGER', 'Set Trigger', 'Set Trigger Commonly known as a "hair-trigger," this weapon retooling allows a blaster or slugthrower to fire with barely a touch of the trigger. This attachment can be applied to any Ranged (Light) or Ranged (Heavy) weapon. Models Include: Custom variants.', 'Weapon', 1, 450, 4, NULL, '[{"key":null,"count":1,"misc_desc":"Automatic [SU][TH] to the first combat check made with this weapon each encounter."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Adds [SU] to the first combat check made with this weapon each encounter"}]'::jsonb, NULL),
  ('SHADOWSHEATH', 'Shadowsheath', 'Shadowsheath Bounty hunters, assassins, and other criminals often have a need to conceal weapons on their bodies to sneak them past guards or get close to a target without arousing alarm. A shadowsheath utilizes optical camouflage technology, but rather than conceal an entire body, its smaller projector is specifically designed to conceal a single weapon when kept in a holster or sheath. This attachment may be attached to any weapon with an encumbrance of 2 or less. Models Include: Merr-Sonn Shadowsheath WCS.', 'Weapon', 1, 1500, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Increases the difficulty of any checks made to detect the sheath or the weapon it holds by two"}]'::jsonb, NULL, NULL),
  ('SHB', 'Shortened Barrel', 'Shortened Barrel Shortened barrels are a handy modification used by spies, plain-clothes law enforcement officers, and anyone needing to conceal the fact that they are carrying a weapon. Little more than a replacement barrel shorter than the standard one, this attachment makes concealing a pistol easier, and can improve the speed of a quick draw. This attachment can only be applied to Ranged (Light) pistol weapons. Models Include: Arakyd SB4 "Stubber", SoroSuub SBSS Reduced Length Barrel.', 'Weapon', 1, 250, 4, ARRAY['Pistol']::text[], '[{"key":null,"count":1,"misc_desc":"Reduces the difficulty of checks made to conceal\r\n          this weapon by 1."},{"key":"RANGESUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":"QUICKDR","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('SHDISCH', 'Shield Discharge Pack', 'Shield Discharge Pack Despite being nearly as ancient as warfare, shields continue to be popular weapons, serving as trusted defenders of warriors on low-tech planets and protecting life and limb of security forces in densely populated areas. While shields are useful weapons already, adding discharge packs to them can allow the wielder to deliver a debilitating shock when detecting a hit. Further, just the sight of a crackling arc of energy wreathing a shield can disturb many would-be attackers, making their strikes far more timid - and far less lethal - than they would have been otherwise. This attachment can only be applied to a shield or buckler.', 'Weapon', 1, 800, 5, ARRAY['Shield']::text[], '[{"key":null,"count":1,"misc_desc":"When wielder suffers hit from Melee, Brawl, or Lightsaber combat check, may spend [TH][TH] or [DE] to cause attacker to suffer 3 strain, ignoring soak."}]'::jsonb, '[{"key":"DISORIENT","count":2,"misc_desc":null},{"key":"DEFSTA","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('SHIENREVGRIP', 'Shien Reverse Grip Customization', 'Shien Reverse Grip Customization Practitioners of Form V sometimes use a reverse grip on their lightsabers to assist in many of the techniques common to that form. Through a few careful adjustments to the grip and balance of their lightsabers, these practitioners can make the weapons more suited to wielding in this manner although the modifications make using a traditional grip somewhat unwieldly in the process. Models Include: None; users must custom make each lightsaber attachment.', 'Weapon', 1, 100, 6, NULL, '[{"key":null,"count":null,"misc_desc":"Wielder adds [AD] to all Lightsaber (Cunning) checks, but adds [TH] to all other Lightsaber checks."}]'::jsonb, NULL, NULL),
  ('SHOCKPULSEMIT', 'Shock Pulse Emitter', 'Shock Pulse Emitter Shock pulse emitters operate along principles similar to a blaster''''s stun setting, but at much shorter effective range—a range short enough to be of little use as weapons in themselves. However, when shock pulse emitters are integrated into weapons intended for close combat to begin with, they become effective combat tools to debilitate opponents and make a finishing blow easier to land. This attachment can be installed on any Melee or Brawl weapon. Models Include: Corellian Personal Defense Stun Pad.', 'Weapon', 2, 1500, 5, NULL, '[{"key":"STUN","count":2,"misc_desc":null}]'::jsonb, '[{"key":"STUN","count":2,"misc_desc":null},{"key":"DISORIENT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('SIGRED', 'Weapon Signature Reduction', 'Weapon Signature Reduction Both the Empire and the galactic security industry use weapon scanners that are capable of detecting a wide variety of weapon components. Even when broken down into several pieces, blasters and other ranged weapons are still liable to be detected, due to the specific technologies and substances that allow them to function as lethal weapons. In order to skirt such inspection and ensure that hidden weapons remain obscured from prying eyes, covert agents have devised modifications that mask or otherwise diminish such signatures in a weapon’s components. Though physical searches still pose some risk of discovery, weapon signature reduction guarantees that scanning equipment used to detect weapons is rendered less effective. Unfortunately, weapon signature reduction is only effective on weapons with an encumbrance rating of 5 or less.', 'Weapon', 1, 1000, 6, NULL, '[{"key":null,"count":1,"misc_desc":"Increase the difficulty checks using scanners to search for this weapon by 2.  Add [SE] to all Mechanics checks to perform maintenance on this weapon."}]'::jsonb, NULL, NULL),
  ('SLUGSUPP', 'Slugthrower Suppressor', 'Slugthrower Suppressor Suppressors are used by assassins and sharpshooters to make their weapons quieter and more difficult to detect when firing. Similar to energy dampers used to silence blasters, suppressors clip or screw onto the end of a weapon''''s barrel, redirecting sound and escaping gases to reduce the noise and muzzle flash a slugthrower produces when fired. While they don''''t make the weapon completely silent they do dramatically reduce its report, making a shooter more difficult to detect. The major downside of using a suppressor is that in reducing the weapon''''s report it also lowers the speed at which a round travels, diminishing the weapon''''s damage in the process. Suppressors can only be used on Ranged (Light) and Ranged (Heavy) slugthrower weapons. Models Include: Czerka Mk. I Suppressor, SoroSuub "Whisperflite" Slugthrower Silencer.', 'Weapon', 1, 100, 4, NULL, '[{"key":null,"count":1,"misc_desc":"Adds [SE][SE] to Perception or Vigilance checks made to locate a concealed shooter firing a silenced slugthrower."}]'::jsonb, NULL, NULL),
  ('SOLARICRYS', 'Solari Crystal', 'Solari Crystal As rare as this type of kyber crystal is, some do find their way into the hands of Force sensitives highly attuned to the light side of the Force. Tales of solari kyber crystals come from the ancient past, and they have long been thought to be mere myths. However, they do exist, and it is a lucky Force user who can find one and make use of it. Or perhaps it is the will of the Force that those most in tune with the light side should happen upon them. They are not put to use lightly, though, for they demand much of their wielder. In exchange, they provide unparalleled protection against incoming fire. A solari crystal causes a lightsaber''''s blade to widen, thereby making much more effective at deflecting blaster bolts. A solari crystal is a lightsaber crystal.', 'Weapon', 3, 16000, 9, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":7,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Reduce strain from Reflect incidental by 1."},{"key":null,"count":1,"misc_desc":"Crystal ceases to function if wielder''s Morality is reduced below 50."}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Reduce cost of Improved Reflect by [TH]"}]'::jsonb, NULL),
  ('SONICSCOPE', 'Sonic Scope', 'Sonic Scope Originally developed to overcome personal cloaking devices and other sensor-baffling defenses, a sonic scope uses ultrasonic sound waves to detect a target and generate a visual representation. With proper calibration, the sonar waves can be set to pass through even duracrete and other solid surfaces. This attachment can be used with any Ranged (Heavy) weapon. Models Include: CryonCorp PL-1 "Second Sight" Scope, SoroSuub Model Z Integrated Sonar System', 'Weapon', 1, 1500, 8, NULL, '[{"key":null,"count":1,"misc_desc":"May observe and target enemies who are completely hidden by solid objects."}]'::jsonb, '[{"key":"COOL","count":1,"misc_desc":null},{"key":"VIGIL","count":1,"misc_desc":null},{"key":"PRECAIM","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('SORIAN', 'Sorian Crystal', 'Sorian Crystal Though none can confirm accurately from which planet these mysterious stones originate, many traders recognize these gems by their radiance. Sorian crystals are said to reflect light in swirling, intricate patterns reminiscent of dancing flames. Because of these gems'''' relative scarcity, few realize that they are in fact kyber crystals. The energy blade formed by a sorian crystal surges briefly with the power whenever it comes into contact with another object moving at high speed - such as another lightsaber. The slight but sudden jolt that emanates from the blade is often enough to throw an attacker off balance, giving the wielder a chance for a counterstrike. While this dded resistance also makes it harder to slice apart an opponent in a single stroke over the course of a long duel between skilled fighters, the unique edge it provides can make the difference between life and death. A sorian crystal is a lightsaber crystal.', 'Weapon', 4, 16000, 9, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When used with the Parry talent, add [BO] to next combat check made against attacker before the end of the next round."}]'::jsonb, '[{"key":"DAMADD","count":3,"misc_desc":null},{"key":"PARRY","count":1,"misc_desc":null},{"key":"DISORIENT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('SPOOFSCAN', 'Spoofing Scanners', 'Spoofing Scanners Some physical alterations, no matter how extensive, can''''t fool the piercing eyes of scanners and electronic detection devices. However, clever Rebels aren''''t without hope. By reducing the energy output of a weapon or by installing jury-rigged scramblers to shield a device from sensory devices, a character can potentially allow the item to evade detection. Characters attempting such an alteration must make a Hard () Mechanics check. This adds to Perception checks that operators using a scanning device make to detect the item. They may spend from the Mechanics check to have the difficulty of such detection checks upgraded once. Unfortunately, the reduction of a weapon''''s energy output does diminish its effectiveness. Each net from the check for reducing a weapon''''s energy output also reduces its damage by one, to a minimum of 1. Characters may spend from the Mechanics check to halve this reduction in damage, rounding up. Only weapons that use energy-based attacks or other advanced devices can have their energy output reduced or signature concealed. This means that slugthrowers and traditional explosive devices cannot be modified in this fashion. In addition, items that require extensive power (such as repeating blasters) cannot have their energy signature reduced. Note that this differs from the scanner-proof hardware weapon attachment, which requires no check for use once it is installed and is more a customization of the weapon than a mechanical alteration.', 'Weapon', 0, NULL, NULL, NULL, '[{"key":null,"count":1,"misc_desc":"Characters attempting such an alteration must make a [B]Hard ([DI][DI][DI]) Mechanics check[b]. This adds [SE] to Perception checks that operators using a scanning device make to detect the item. They may spend [TR] from the Mechanics check to have the difficulty of such detection checks upgraded once."},{"key":null,"count":1,"misc_desc":"Each net [SU] from the check for reducing a weapon''s energy output also reduces its damage by one, to a minimum of 1. Characters may spend [TR] from the Mechanics check to halve this reduction in damage, rounding up."},{"key":null,"count":1,"misc_desc":"Only weapons that use energy-based attacks or other advanced devices can have their energy output reduced or signature concealed. This means that slugthrowers and traditional explosive devices cannot be modified in this fashion. In addition, items that require extensive power (such as repeating blasters) cannot have their energy signature reduced."}]'::jsonb, NULL, NULL),
  ('STEALTHFGEN', 'Stealth Field Generator', 'Stealth Field Generator Produced by a number of stealth technology companies, stealth field generators are the final word in personal active stealth technology. They use a combination of optical camouflage, low-output cloaking technology, active electromagnetic dampers, electronic acoustic bafflers, and thermal shielding to make a user virtually invisible to both the naked eye and to most scanners. These systems are not perfect, however. Users still need to know how to move stealthily and how to use cover and shadows to their advantage. Users also cannot move faster than a walk, or the stealth field will break down. This attachment can be applied to any armor. Models Include: Fabritech XO-A "Vanish l" Personal Stealth Generator, Kerner Corp. "Defel" Cloaking Belt.', 'Armor', 2, 3800, 7, NULL, '[{"key":null,"count":1,"misc_desc":"Upgrades the difficulty of all opposed Perception checks to spot the wearer once."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Add [SE] to opposed Perception checks to notice the wearer"}]'::jsonb, NULL),
  ('STRIPDOWN', 'Stripped Down', 'Stripped Down By removing redundant components and stripping down the body, it is possible to significantly reduce the weight and profile of a blaster or other weapon. A weapon modified this way is more easily carried and transported and can be better hidden under a coat or among other equipment. The attachment can be used with any Ranged (Light) or Ranged (Heavy) weapon. Models Include: None', 'Weapon', 3, 250, 4, NULL, '[{"key":"ENCSUB","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"Add [SE] to Perception checks to find the weapon when hidden."}]'::jsonb, '[{"key":"ENCSUB","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('STUNBLAST', 'Stun Blaster Attachment', 'Stun Blaster Attachment Force sensitives trained or experienced in other fields prior to embarking on their current path may feel more comfortable using a ranged weapon before resorting to their lightsabers. Others may have reason to disguise their lightsabers, yet retain immediate access to them. Still others reason that if the threat of an opponent can be eliminated at range, so much the better for all concerned. While carrying a blaster pistol is one solution, some prefer a melding of blaster and lightsaber, perhaps believing that a personal weapon best reflects the Force user when it represents all aspects of the user''''s life, both present and past. Still, the tenets of the Jedi Order apply, and life is to be preserved if at all possible. The stun blaster attachment is seen as an acceptable compromise in these situations. By stripping down an otherwise functional stun blaster, wiring it into the power supply of a lightsaber hilt, and bolting the resulting device to that hilt, a Force user can make use of the blaster without relinquishing immediate access to the lightsaber. This cannibalized stun blaster has a shorter range. Due to the energy draw on the lightsaber''''s power supply, it cannot be used simultaneously with the blade, but it is often a useful addition to the wielder''''s weaponry. This attachment has saved more than one life on both ends of the lightsaber.', 'Weapon', 2, 750, 5, ARRAY['Lightsaber','Lightsaber Hilt']::text[], NULL, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"SUBQUALUNWIELDY","count":1,"misc_desc":null},{"key":"DISORIENT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('STUNMAT', 'Stun Matrix', 'Stun Matrix A stun matrix is an additional defensive option for armor. Instead of enhancing the wearer''''s defenses directly, it unleashes a punishing pulse of energy that weakens the attacker in the hope of preventing a second strike. Installing this attachment requires the addition of insulation to protect the wearer form the effects of the stun matrix on top of the setup of the self charging battery and of the stun matrix itself. While the device is relatively bulky, it can be concealed if integrated subtly into a heavy armor frame, the better to surprise would-be attackers. This attachment can be applied to any armor that could logically benefit from having a stun matrix added.', 'Armor', 3, 1750, 3, NULL, '[{"key":"ENCADD","count":1,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When suffering hit from Melee, Brawl, or Lightsaber combat check, may spend [TH][TH] or [DE] to disorient attacker for 2 rounds."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"May spend [TH][TH][TH] or [DE] to immobilize attacker for 1 round"},{"key":null,"count":1,"misc_desc":"May spend [DE] to stagger attacker for 1 round"}]'::jsonb, NULL),
  ('STUNONLYBLASTER', 'Stun-Only Blaster Modification', 'Stun-Only Blaster Modification Add this attachment to any blaster pistol or carbine to make it stun-only. A blaster with this modification costs half the normal price.', 'Weapon', 0, NULL, 1, ARRAY['Blaster Carbine','Blaster Pistol']::text[], '[{"key":"REMQUALSTUNSETTING","count":null,"misc_desc":null},{"key":"STUNDAMAGE","count":null,"misc_desc":null},{"key":"PRICEHALF","count":null,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('STUNPULSE', 'Stun Pulse', 'Stun Pulse A stun pulse attachment deals an electric shock to the target, in addition to its weapon''''s normal damage. Generally attached to truncheons or bludgeoning weapons, stun pulses are often used by law enforcement to disable suspects without killing them. A stun pulse can be attached to any bludgeoning Melee or Brawl weapon. Models Include: CoroTech EV45 Pulse Coil, SoroSuub "Enforcer" Stunner.', 'Weapon', 1, 250, 4, ARRAY['Bludgeoning Melee','Bludgeoning Brawl']::text[], '[{"key":"STUN","count":2,"misc_desc":null}]'::jsonb, '[{"key":"STUN","count":3,"misc_desc":null}]'::jsonb, NULL),
  ('SUPHILT', 'Superior Hilt Personalization', 'Superior Hilt Personalization While most lightsabers are austere and utilitarian, some Jedi have been known to personalize their weapons to better suit their tastes and styles. Numerous cosmetic or practical enhancements can be applied to a lightsaber, from rare metals and precious gemstones to customized grips and locking activating switches. Models Include: None.', 'Weapon', 1, 5000, 6, ARRAY['Lightsaber']::text[], '[{"key":"SUPERIOR","count":null,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('SWC', 'Superior Weapon Customization', 'Superior Weapon Customization Even the simplest weapon can benefit from a craftsman''''s touch. A skilled weaponsmith can tweak a weapon to its owner''''s exacting specifications, turning a blunt instrument into a honed and deadly weapon of war. Models Include: None.', 'Weapon', 1, 5000, 6, NULL, '[{"key":"SUPERIOR","count":null,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('TAINTNIGHT', 'Tainted Nightsister Crystal', 'Tainted Nightsister Crystal The Nightsisters rose and fell as a faction untouched by the conflicts between Jedi and Sith. As such, they had little time to adopt the iconic lightsabers as their weapons of choice. This has not stopped dark side Mystics from trying to fuse Nightsister magic with Sith weaponry. Most experiments yield no fruit, but some have made for particularly terrifying advancements. Tainted Nightsister crystals were once pure Kyber crystals. Soaking them in Dathomiri Waters of Life perverts their connection to the Force. The resulting blade emits a choking, putrid green smoke when active.', 'Weapon', 2, 13000, 10, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"DISORIENT","count":3,"misc_desc":null},{"key":"VICIOUS","count":4,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"DISORIENT","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('TARGCOMP', '"Accu-Strike" Integrated Targeting Computer', '"Accu-Strike" Integrated Targeting Computer Complex and sophisticated attachments, targeting systems integrate an advanced targeting computer and sensor suite, providing a constant stream of data to the user. Depending on the model, this information may be delivered by audio or on a visor HUD. Some particularly advanced systems incorporate small vibro-motors installed in the armor''''s gloves or gauntlets and wired to the helmet system, which subtly adjust the user''''s hands to enhance accuracy.', 'Armor', 1, 3000, 7, NULL, '[{"key":null,"count":null,"misc_desc":"Add [BOOST] to all Ranged attacks at long or extreme range."}]'::jsonb, '[{"key":"NATMAR","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('THISSCOIL', 'Thisspiasian Stabilizing Coils', 'Thisspiasian Stabilizing Coils Thisspiasian weaponcraft focused, for centuries, on grace above all else. The antique manners of the Blood Court may embarrass the average citizen, but one can''''t argue with their results. Traditional weapons from Thisspias correct for even the clumsiest of maneuvers. Survivors of the Jedi Purge return to this philosophy to strengthen their weaponry, Thisspiasian stabilizing coils are often stylized as a long tail that wraps itself around the hilt of a lightsaber. Rotating and curling with each movement, this device keeps the blade perfectly balanced.', 'Weapon', 1, 5500, 5, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"SETBACKSUB","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('THOLOHILT', 'Tholothian Heartwood Hilt', 'Tholothian Heartwood Hilt While most lightsabers have synthetic hilts, Tholothian Jedi preferred a more organic approach. At their height, they crafted heartwood hilts from the timber of still-living trees The wood was then preserved in a specialized ritual-one more often used when a heartwood tree was dying. The resulting hilt is resistant to decay and can house a lightsaber''''s apparatus. The resulting lightsabers are beautiful works of art as much as they are weapons. The resins used to preserve the timber increase its weight, and wielders must take appropriate care in using them. This often translates to a stronger and more deliberate strike when this weapon does connect.', 'Weapon', 1, 8000, 7, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"ENCADD","count":1,"misc_desc":null},{"key":"DAMADD","count":2,"misc_desc":null},{"key":null,"count":1,"misc_desc":"GM may spend [TH][TH][TH][TH] or [DE] to damage by one step."}]'::jsonb, NULL, NULL),
  ('THREATMON', 'Threat Monitor', 'Threat Monitor A threat monitor is a suite of motion detectors, electroreceptors, and photoreceptors that constantly monitors the armor wearer''''s vicinity and, through directional auditory or electrical cues, warns the wearer of imminent threats and incoming attacks. While many find threat monitors somewhat annoying to wear, they can provide a critical edge in life-or-death situations. This attachment can only be used on armor and is typically integrated into the helmet, visor, or another place where the user can easily see it at all times. Models Include: Atlas Corp Pan-directional Alert Scanner, Galactic Electronics Z-12 Threat Assessor.', 'Armor', 1, 750, 4, NULL, '[{"key":"ADVADDINIT","count":1,"misc_desc":null}]'::jsonb, '[{"key":"QUICKST","count":1,"misc_desc":null},{"key":"ADVADDINIT","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('TOS', 'Telescopic Optical Sight', 'Telescopic Optical Sight Popular with marksmen and snipers, this attachment consists of a long tube attached to the top of a weapon with a number of precisely ground lens elements protected by an impact-resistant housing. The resulting scope magnifies distant images for long-range shooting. This attachment can be used on any ranged weapon (with the exception of one-use weapons like grenades, or weapons like flame projectors that would not realistically benefit from a sight). Models Include: Merr-Sonn 80Z Telescopic Optical Sight, Zikon Optics Model 40 Marksman Scope.', 'Weapon', 1, 250, 1, ARRAY['Ranged']::text[], '[{"key":"DIFFSUBLONGEXT","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('TRACKSYS', 'Tracking System', 'Tracking System Through a series of specialized computer systems and sensors, this attachment collects and processes data from the wearer''''s surroundings to follow and predict the movements of designated targets. A heads-up display integrated into a helmet or visor feeds the wearer this information onto an overly of their surroundings. The systems are not limited to local targets, either, but can follow signals from distant communicators or tags and process optimal routes towards them. Tracking systems in armor are typically designed to operate alongside similar equipment, and are often able to integrate with other systems to a greater effect than the sum of their parts. This attachment can be installed on any armor. Models Include: Galkor Solutions W-7 Locator Array.', 'Armor', 1, 1000, 7, NULL, '[{"key":null,"count":1,"misc_desc":"As a maneuver, may designate a target for tracking.  Only one target may be designated at a time."},{"key":null,"count":1,"misc_desc":"Upgrade the ability of checks to track a designated target once."}]'::jsonb, '[{"key":"VIGIL","count":1,"misc_desc":null},{"key":"SURV","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('TRAINEMIT', 'Training Lightsaber Emitter', 'Training Lightsaber Emitter In the days of the Republic, the Jedi allowed their younglings to train with "training sabers," non-lethal versions of their famous energy blades. A training lightsaber is almost the same as a standard lightsaber; however, the crystal is replaced with a training emitter. The training emitter creates a blade that is completely non-lethal, and at most can generate a stun shock. A training emitter is a lightsaber crystal. Models Include: None.', 'Weapon', 2, 100, 6, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":null,"misc_desc":null},{"key":"STUNDAMAGE","count":null,"misc_desc":null},{"key":"REMQUALSUNDER","count":null,"misc_desc":null},{"key":"REMQUALBREACH","count":null,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('TRIPOD', 'Tripod Mount', 'Tripod Mount Designed for use with the heaviest man-portable weapons, tripods are a common sight among heavy weapon squads. Used in static weapon emplacements to support heavy squad support weapons such as the Imperial Army''''s E-Web heavy repeating blaster, tripods use a number of different technologies—from self-extending hydraulics to tiny, low-output repulsorlift generators—to stabilize heavy weapons for firing. This attachment is only for use on light repeating blasters and heavy repeating blasters, as well as any portable Gunnery weapons. Setting up a tripod takes two preparation maneuvers. Models Include: BlasTech 3R Heavy Weapon Tripod Mount.', 'Weapon', 2, 250, 3, ARRAY['Portable Gunnery']::text[], '[{"key":"CUMBERSOME","count":-3,"misc_desc":null}]'::jsonb, '[{"key":"CUMBERSOME","count":-2,"misc_desc":null}]'::jsonb, NULL),
  ('TSS', 'Thermal Shielding System', 'Thermal Shielding System Utilizing both active and passive cooling systems, along with an insulated body glove and special coatings on the armor plates, this attachment allows a wearer to withstand dangerously high temperatures. This thermal shielding is proof against open flames, molten rock and steel, intense heat, and even some forms of radiation. This attachment can be installed on any armor that covers the entire body and can be sealed. Models Include: Atlas Corp Model 451 Heat Exchanger, Min-Dal 3100 Firebrand Suit, Kaminoan Armorsmiths Thermal Shielding System.', 'Armor', 1, 1000, 3, ARRAY['Sealed']::text[], '[{"key":null,"count":1,"misc_desc":"Reduces the difficulty of Resilience checks made\r\n          to resist the effects of fire and extreme heat by one.\r\n          Removes up to [SETBACK][SETBACK] added to checks\r\n          due to extreme heat or fire."}]'::jsonb, NULL, NULL),
  ('UBFP', 'Under-Barrel Flame Projector', 'Under-Barrel Flame Projector Uncommon but highly effective, the Firestorm by Czerka is a small, under-barrel flame projector designed to give an infantryman extra punch at short range. Illegal on many worlds and classified as a terror weapon, these weapons are typically used by only the most desperate or callous individuals. This attachment can only be applied to rifle-sized weapons. Models Include: Czerka "Firestorm" Under-barrel Flame Projector, Merr-Sonn XR14 Sunsear Flame Projector, SoroSuub "Inferno" Auxiliary Flamer.', 'Weapon', 2, 3000, 5, ARRAY['Rifle','Heavy Rifle','Carbine']::text[], '[{"key":null,"count":1,"misc_desc":"Adds a flame projector to the weapon."},{"key":"CUMBERSOME","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('UBGL', 'Under-Barrel Grenade Launcher', 'Under-Barrel Grenade Launcher Under-barrel grenade launchers are designed to give soldiers or squads heavy anti-infantry or light anti-vehicle capabilities in a small package. This attachment consists of a basic, smooth-bore barrel attached to a magazine with an automatic feed system. It carries up to six grenades and is fired by a simple press of a button. It adds extra weight to the weapon it''''s mounted to, however, which makes the entire assembly quite barrel heavy. This attachment can only be applied to rifle-sized weapons (Ranged (Heavy) weapons). Models Include: Czerka "Thumper" Under-barrel Grenade Launcher, SoroSuub XA203 Auxiliary Grenade Launcher, Zone Control "Viper" Under-Barrel Grenade Launcher.', 'Weapon', 2, 2000, 5, ARRAY['Rifle','Heavy Rifle','Carbine']::text[], '[{"key":null,"count":1,"misc_desc":"Weapon can fire grenades using the grenade profile, Ranged (Heavy) skill, and has Medium range."},{"key":"CUMBERSOME","count":2,"misc_desc":null},{"key":"ENCADD","count":2,"misc_desc":null},{"key":"LIMITEDAMMO","count":1,"misc_desc":null}]'::jsonb, '[{"key":"LIMITEDAMMO","count":5,"misc_desc":null}]'::jsonb, NULL),
  ('UNDERSCATTER', 'Underslung Scattergun', 'Underslung Scattergun An ungainly attachment, an underslung scattergun is a single-shot slugthrower that can be attached to another weapon. While hardly what one would call subtle, it nonetheless has found a ready market amongst some bounty hunters and gunslingers due to its low cost and impressive effect. This attachment can only applied to pistol and rifle-sized weapons. Models Include: Czerka "Leveller" Under-barrel Scattergun, Merr-Sonn XZ03 Scattershell Slugthrower Attachment, Goseia Heavy Industries Concern "Troubleshooter" Underslung Slugthrower.', 'Weapon', 3, 750, 5, ARRAY['Pistol','Rifle']::text[], '[{"key":null,"count":1,"misc_desc":"Adds a scattergun to the weapon."},{"key":"CUMBERSOME","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('UNSTKYBER', 'Unstable Kyber Crystal', 'Unstable Kyber Crystal The Kyber crystal is the heart of a lightsaber, but as with the hearts of organic beings, there can be imperfections. There are many opportunities between mining and use for a crystal to become unstable. It could develop hairline fractures in initial transit. Its wielder might subject it to extreme stress in use. Either way, power can begin to leak out of the crystal itself. Under normal circumstances, these imperfections will not affect a lightsaber''''s performance. With the right knowledge, however, a Force user can harness the leaking energy for their own ends. By performing a lengthy ritual with the lightsaber, a Mystic can draw some of its power into themselves for a time.', 'Weapon', 2, 16000, 10, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"As maneuver, increase Force rating by 1. This persists until using the extra [FO] to fuel Force talent or Force power. However, GM may spend [TH][TH][TH][TH] or [DE] to cause lightsaber to sputter and fail, if this happens may not reignite lightsaber for one hour."}]'::jsonb, NULL, NULL),
  ('UTILARM', 'Utility Arm', 'Utility Arm For some species, it''''s a mystery how humans and their ilk get by with only two arms. In fact, it''''s often said that the first armor-mounted utility arm was invented by a Dug Engineer, although another tale attributes its origin to a cybernetics manufacturer with a product surplus. Regardless of its origin, the utility arm is now a common tool for Engineers and technicians of all species. Mounted on a harness or suit of combat armor, a utility arm is a mechanical appendage similar in function to many cybernetic and droid arms and ending in a manipulating "hand." Although utility arms are most often used to increase workshop productivity, combatants of all kinds have found them useful on the battlefield.', 'Armor', 2, 2000, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Provides character with an additional mechanical arm that can function as one of the character''s normal limbs."},{"key":null,"count":1,"misc_desc":"Adds [BO] to Mechanics checks."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Adds [BO] to Mechanics checks."},{"key":null,"count":1,"misc_desc":"May spend 1 strain to gain an additional free maneuver per turn (still limited to two maneuvers per turn)."}]'::jsonb, NULL),
  ('VACUUM', 'Vacuum Sealed', 'Vacuum Sealed Full body armor can be designed to be sealed against a vacuum, allowing the user to operate in space. This modification provides the armor with enough air and insulation to survive for up to 10 minutes, and obviously also protects against adverse atmospheric environments. This can only be applied to laminate or battle armor. Models Include: Numerous Variants.', 'Armor', 1, 1000, 3, ARRAY['Sealable']::text[], '[{"key":null,"count":null,"misc_desc":"Allows the user to ignore the effects of\r\n          vacuum or poisonous atmospheric environments\r\n          for up to 10 minutes."},{"key":"SEALED","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('VARPCRYST', 'Varpeline Crystal', 'Varpeline Crystal Varpeline crystals are hard, super dense minerals found on the Outer Rim worlds of Mearalis II. Ranging in color from white to a rich gold, they are scattered throughout Mearalis II''''s extensive mountain ranges. When properly worked, varpeline crystals can be used to slice through nearly any substance known in the galaxy. While they are typically used in industrial cutting machinery or precision fabrication instruments, these stones are occasionally used to great effect as lightsaber crystals. When installed in a lightsaber, this crystal produces a blade that emits a short, sharp ringing tone when it strikes an object. A lightsaber equipped with a varpeline crystal can often cut through the thickest armor or toughest materials, and have a disturbing tendency to dismember living targets.', 'Weapon', 2, 14000, 9, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":8,"misc_desc":null},{"key":"CRITSET","count":3,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":1,"misc_desc":"When spending [TR] to inflict Critical Injury, may spend additional [TR] to automatically inflict Maimed Critical Injury."}]'::jsonb, '[{"key":"VICIOUS","count":2,"misc_desc":null},{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('VIBBAY', 'Vibro-Bayonet', 'Vibro-Bayonet Although most fights are resolved with exchanges of blaster fire, a close-range firefight can quickly turn into a melee. When this happens, it pays to be prepared. Because the time it takes to draw a blade can mean the difference between life and death, some spacers equip their blasters with vibro-bayonets, essentially vibroblades mounted on the barrel of a gun. While a vibro-spear is not many Technicians'''' weapon of choice, having one at hand is considerably better than being effectively unarmed when combat takes place in such cramped quarters as the belly of a starship. This attachment can be applied to any Ranged (Heavy) weapon that could be logically mount a bayonet. Models Include: Czerka Arms "Last Resort" Vibro-Bayonet, Merr-Sonn Model 3 Combat Attachment', 'Weapon', 1, 500, 3, NULL, '[{"key":null,"count":1,"misc_desc":"Adds a vibro-bayonet to the weapon"}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('WALKHILT', 'Walking Stick Hilt Disguise', 'Walking Stick Hilt Disguise Often, particularly elderly Jedi constructed their lightsabers in the body of a sturdy walking stick. If the blade is a Jedi''''s life, why shouldn''''t it make things a little easier? The pure utility of this practice fell out of favor with the Jedi Order. Most elderly Jedi did not, after all, survive the Purge. Survivors, though, found a similar technique could hide their weapons in plain sight. This concealment does come with a cost. The awkward size and inconsistent weighting often interferes with use in heated combat.', 'Weapon', 1, 2500, 6, ARRAY['Lightsaber','Lightsaber Hilt']::text[], '[{"key":null,"count":1,"misc_desc":"Unless ignited, must pass [B]Formidable ([DI][DI][DI][DI][DI]) Perception[b] or [B]Vigilance check[b] to notice it is not a regular walking stick."},{"key":"INACCURATE","count":1,"misc_desc":null}]'::jsonb, '[{"key":"SUBQUALINACCURATE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('WATERRECLSUIT', 'Water Reclamation Suit', 'Water Reclamation Suit Water reclamation systems are popular with scouts and hermits, especially those living or working on arid worlds. Produced by a variety of wilderness outfitters, like Survival Equipment Inc. and Gandorthral Atmospherics, these systems collect a body''''s waste moisture and distill it for drinking. Typically, the consist of a tight bodysuit worn under a suit of armor, that covers a wearer to the neck, wrists, and ankles, along with a matching pair of gloves and a filtermask that covers the mouth and nose. Made from layers of synthetic fibermesh, the suit wicks sweat away from the skin and purifies it by means of integrated filtration media. It also collects waste moisture from the mouth and nose by means of the filtermask. The water is then collected in pouches spread across the suit and can either be decanted into a larger container or drunk straight from the suit by means of a long, flexible tube connected to the suit''''s back. Adding a Water Reclamation System to a suit of armor allows an individual to operate much longer in desolate environments without fear of running out of water. This attachment can be applied to any armor that could logically integrate the necessary pouches and tubing.', 'Armor', 2, 500, 4, NULL, '[{"key":null,"count":null,"misc_desc":"Upgrades ability of Resilience and Survival checks made in dry or hot environments due to scarcity of water twice."}]'::jsonb, NULL, NULL),
  ('WEIGHTHEAD', 'Weighted Head', 'Weighted Head Weapons designed to bludgeon foes to unconsciousness or death often benefit from extra weight added to the striking surface. This can be accomplished through using heavier materials in the construction, or just by adding metal bands or studs to the business end. Reinforced "knuckles" can be added to some brawling weapons for similar effect. This attachment can only be added to bludgeoning Melee or Brawl weapons. Models Include: None.', 'Weapon', 2, 250, 3, ARRAY['Bludgeoning Melee','Bludgeoning Brawl']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"CONCUSSIVE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('WEPHARN', 'Weapon Harness', 'Weapon Harness Designed to allow a single sentient to field even the heaviest man-portable weapons with no support, weapon harnesses are rare among the Outer Rim territories. Worn over the shoulders and belted around the midsection or torso, weapon harnesses consist of a series of load-bearing straps and harnesses connected to a gyro-stabilized, power-assisted boom arm attached to a heavy weapon. Powered by a tiny rechargeable power pack, the harness offers its user enhanced stability and strength when using heavy weapons. This attachment can only be used with Ranged (Heavy) and Gunnery weapons. Models Include: Arakyd WW480 "Goliath" Weapon Harness, Galactic Arms HR12 Power Harness, SoroSuub "Little Giant" Heavy Weapon Power Assist.', 'Weapon', 2, 500, 2, NULL, '[{"key":"CUMBERSOME","count":-2,"misc_desc":null}]'::jsonb, '[{"key":"BRA","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('WEPSLING', 'Weapon Sling', 'Weapon Sling Slings are lengths of hide or synthetic fabric designed to allow easy handling of long arms like blaster rifles and slugthrower rifles. They come in a dizzying array of styles, from the simple adjustable single-strap sling for carrying a weapon off the shoulder to multi-strap slings made of specialized materials that allow for any number of custom sling configurations. These attachments can only be used with Ranged (Heavy) weapons. Models Include: Custom-tooled Bantha hide sling, Tactical three-point sling, Quick-release one-point drop sling.', 'Weapon', 1, 100, NULL, NULL, '[{"key":"CUMBERSOME","count":-1,"misc_desc":null}]'::jsonb, '[{"key":"QUICKDR","count":null,"misc_desc":null}]'::jsonb, NULL),
  ('WRISTMOUNT', 'Model 2 Wrist Mount', 'Model 2 Wrist Mount Originally developed to allow species without opposable thumbs to use pistols, a wrist mount ensures that the user always has a weapon ready while keeping his hands free. Many users choose wrist mounts as a way to pack further firepower, while it is simply an aesthetic choice for some. Wrist-mounted weapons can be fired with a pressure-sensitive palm trigger, a particular wrist motion, or even by neural link. This attachment can be applied to any Ranged (Light) weapon.', 'Weapon', 2, 275, 5, NULL, '[{"key":null,"count":1,"misc_desc":"Weapon can be worn on the wrist, freeing user''s hands."}]'::jsonb, NULL, NULL),
  ('XCITEOVER', 'XCiter Overcharge', 'XCiter Overcharge A common—and dangerous—modification among espionage agents, an XCiter Overcharge allows an individual to empty a blaster''''s energy cell in a single, extremely powerful shot. This increases the output for an emergency kick, but it runs the risk of destroying the weapon and harming the user. While typically applied to holdout blasters, this attachment can be applied to any personal blaster weapon. Models Include: BlasTech "Nova" Overcharge System.', 'Weapon', 2, 1100, 7, ARRAY['Blaster']::text[], '[{"key":null,"count":1,"misc_desc":"As an incidental, shooters may overcharge the XCiter on their blaster. This gives the weapon to Prepare 1 item quality and increases the damage on the next attack by 4. Once it is fired the weapon runs out of ammo and must be recharged."},{"key":null,"count":1,"misc_desc":"GMs may spend [TH][TH][TH] or [DE] from any combat check involving an overcharged shot with this weapon to cause the weapon to explode and deal full damage to the shooter."}]'::jsonb, NULL, NULL),
  ('ASCENGUN', 'Ascension Gun', 'Ascension Gun Ascension guns are tools used to traverse difficult environments, from steep cliffs to urban battlefields. The frame resembles a gun barrel, but instead of a blaster bolt, it fires a grappling hook and tether that can latch onto most surfaces, then reel in the gun and its bearer with a localized repulsor field. Some variations of the ascension gun also use magnetized grapnels that can stick to sheer surfaces. "Ascension gun" is something of a misnomer, other used to refer not only to the attachment, but to modified blasters. Models Include: SoroSuub S-A Grappling Launcher.', 'Weapon', 1, 500, 4, ARRAY['Blaster']::text[], '[{"key":null,"count":null,"misc_desc":"User may fire  ascension gun at an anchor point within medium range with an [B]Easy ([DI]) Ranged Light[b] or [B]Coordination check[b], adding [SE] for precise placement.  May asend one range band every round."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add [BO] to checks to fire ascension gun"},{"key":null,"count":1,"misc_desc":"Increase ascension gun speed by one range band per round"}]'::jsonb, NULL),
  ('AUGVIBROMOTOR', 'Augmented Vibro-Motor', 'Augmented Vibro-Motor The cutting edge of a vibro weapon''''s blade is made many times more dangerous than that of a standard blade by the power of the weapon''''s rapid vibro-motor, which turns the wielder''''s slightest motion into a powerful and potentioally lethal stroke. Naturally, those who favor such weapons often look to the vibro-motor first when modifying their weapon. Enhancing the output of a vibro weapon''''s motor can make the weapon even more powerful, capable of shearing through armored plating with ease-provided the wielder can control the weapon''''s more active motions. This attachment can be installed on any vibro weapon.', 'Weapon', 2, 500, 4, ARRAY['Powered Melee','Powered Brawl']::text[], '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"CUMBERSOME","count":3,"misc_desc":null}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null},{"key":"CUMBERSOME","count":-1,"misc_desc":null}]'::jsonb, NULL),
  ('BIOSUPPORT', 'Bio-Support Dispenser', 'Bio-Support Dispenser Sophisticated medical technology integrated into armor can enhance the effects of in-combat treatments through carefully regulated and distributed dosages. This system applies medication automatically as the wearer''''s vitals begin to suffer, and it includes an internal bacta reservoir for sealing the most grievous injuries. This attachment may only be installed on a fully enclosed suit of armor, such as laminate, clone trooper, or heavy battle armor.', 'Armor', 1, 4000, 6, ARRAY['Full Body']::text[], '[{"key":null,"count":null,"misc_desc":"When healing strain at end of encounter, also heal 1 wound if suffered any wounds during encounter."},{"key":null,"count":null,"misc_desc":"First time wounds exceed threshold in an encounter, armor automatically applies a stimpack."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Heal 1 additional wound at end of encounter"}]'::jsonb, NULL),
  ('CEREADORN', 'Cermonial Adornment', 'Cermonial Adornment Diplomats and their retinues typically avoid armor and weapons, the better to clearly signal their sincerity. However, at times, even diplomacy is dangerous enough to warrant looking into personal protection. Those who seek a compromise between protecting their lives and putting others at easy sometimes don ornamented armor with a ceremonial style that downplays its combat-oriented nature. The best armor of this type is as functional as it is beautiful, but usually brings an attendant cost in mobility due to the elaborate decorations over the protective wear. This attachment may be installed on any armor, although the GM may alter its effects for particularly intimidating or heavy armor.', 'Armor', 0, 2500, 4, NULL, '[{"key":null,"count":null,"misc_desc":"Removes [SE][SE] from social skill checks due to wearing armor in socially inappropriate situations."},{"key":null,"count":null,"misc_desc":"Adds [SE] to Coordination checks."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Remove [SE] from Coordination checks"}]'::jsonb, NULL),
  ('CLONEFIRE', 'Clone Firing Key', 'Clone Firing Key One of the early initiatives the Kaminoans considered when developing equipment for the clone troopers was to code their equipment specifically for the clone genetic sequence, to prevent looting and sabotage. The notion was eventually abandoned as an unnecessary cost, despite the savings from having a single genetic sequence shared across an entire army, but prototypes of the technology were made. In some cases, clone firing keys have been commissioned for clone units operating deep behind enemy lines. A weapon with this system installed reads the genetic sequence of the combatant holding it and does not fire unless the sequence matches that of an authorized wielder: normally, a clone. This attachment can be installed on any personal blaster weapon.', 'Weapon', 1, 250, 7, ARRAY['Blaster']::text[], '[{"key":null,"count":null,"misc_desc":"This weapon functions only in the hands of a clone."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Authorize one non-clone genetic sequence."}]'::jsonb, NULL),
  ('COMBTEST', 'Combat Tested', 'Combat Tested Over the course of numerous battles, combatants can make a variety of minor personalizations and tweaks to their gear, from notches for successful missions or targets destroyed carved into the butts of rifles, to the attachment of trophies taken from enemy droids or the battlefield. Weapons customized in this way become comforting reminders of victories past, helping their wielders stay calm under fire and in tough situations, Such personalizations can be installed on any weapon that the owner has used through extended periods of combat, as determined by the GM.', 'Weapon', 0, 50, 3, NULL, '[{"key":null,"count":null,"misc_desc":"Add [BO] to Discipline checks."}]'::jsonb, '[{"key":null,"count":1,"misc_desc":"Add [BO] to check to resist fear."}]'::jsonb, NULL),
  ('CORTFOR', 'Cortosis Forging', 'Cortosis Forging For most, dueling a Jedi is a fool''''s errand, and even more so in close combat, where their lightsaber ditate the terms of battle. If they can afford it, bounty hunters and Separatist agents who believe they might need to pit their blade against a lightsaber purchase a vibro weapon made of cortosis alloy. This can give them a fighting chance against the deadliest weapons in the galaxy. This attachment can be installed on any Melee weapon.', 'Weapon', 1, 8000, 8, NULL, '[{"key":"CORTOSIS","count":1,"misc_desc":null}]'::jsonb, '[{"key":"PIERCE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('INSFIRMECH', 'Insulated Firing Mechanism', 'Insulated Firing Mechanism One of the most insidious dangers of the battlefield comes not from the foes compatants face, but from the risks of their own gear failing. Regular maintenance and examination of weapons under heavy use is a must for soldiers and mercenaries alike, but sometimes modification of a weapon can make the concerns less grave. By removing complex, failure-prone regulatory circuitry and replacing it with more basic analog systems, blasters become easier to maintain and less prone to failure or damage.This attachment can be installed on any personal-scale blaster weapon. Models Include: Czerka Part Replacement Kit NX3-4r, BlasTech "My First Blaster" Safety Kit.', 'Weapon', 1, 1000, 7, ARRAY['Blaster']::text[], '[{"key":null,"count":null,"misc_desc":"Increases [AD] or [TH] cost of any effect that damages the weapon (such as Sunder) by one."},{"key":"PREPARE","count":1,"misc_desc":null},{"key":null,"count":null,"misc_desc":"Repairs to the weapon cost half as much."}]'::jsonb, '[{"key":"PREPARE","count":-1,"misc_desc":null}]'::jsonb, NULL),
  ('IONFOCCOIL', 'Ionizing Focusing Coils', 'Ionizing Focusing Coils Dealing with the droid army of the CIS has made advancements in ion technology a high priority for Republic military researchers and contractors, although research in the field has produced mixed results. In an effort to make blaster weapons more damaging against droids, some manufacturers have begun offering modified focusing voils that ionize blaster gas as it is fired, granting increased stopping power against mechanical targets. However, adequately shielding the internal circuits of the blasters against the ionized gas has proven difficult, making such weapons temperamental at best. Clone detachments with a chance to customize their gear sometimes requisition these altered coils, while independent operators who anticipate interference from droid security forces or similar threats may also invest in the technology. Models Include: BlasTech "Sparker" Ionization Coils.', 'Weapon', 2, 800, 5, ARRAY['Blaster']::text[], '[{"key":null,"count":null,"misc_desc":"Increases damage by +2 versus droids."},{"key":null,"count":null,"misc_desc":"Opponents may spend [TH][TH] or [DE] to damage weapon by one step."}]'::jsonb, '[{"key":null,"count":2,"misc_desc":"Increases damage by +1 versus droids"},{"key":null,"count":1,"misc_desc":"Decreases critical rating by 1 versus droids"},{"key":null,"count":1,"misc_desc":"Increases [TH] required to backfire by 1"}]'::jsonb, NULL),
  ('FUSIONSHUNT', 'Fusion Shunt', 'Fusion Shunt A lightsaber is more than just a weapon. It is a symbol, a badge of office-and a tool. When its wielder is faced with a situation that requires that latter approach, a lightsaber can carve through obstacle or debric to clear a path forward. Some Jedi modify their lightsaber''''s power output to allow a secondary "fusion shunt" mode for the blade, amplifying the power and profile of the blade. The wielder must take great care to keep the blade''''s motions precise, as the energy pours forth from the emitter while the shunt is active.', 'Weapon', 1, 2000, 6, NULL, '[{"key":null,"count":null,"misc_desc":"Activating fusion shunt requires a maneuver.  All combat checks suffer [TH][TH][TH] when shunt is activated."},{"key":null,"count":null,"misc_desc":"Lightsaber''s Breach quality increases by 1 when shunt is active."}]'::jsonb, NULL, NULL),
  ('IONEMIT', 'Ionizing Emitter Matrix', 'Ionizing Emitter Matrix Few droids can stand up to a lightsaber, but some heavily reinforced droid models have been known to fight through the destruction of their limbs and even some of their core systems to achieve their objectives. Some Jedi have taken to tuning their lightsabers specifically to deal with these foes, the better to bring the war to a close by disabling the droid armies. With the right modifications, a lightsaber can be made to emit a low-level ion pulse as it strikes, although such modulation reduces its overall energy output.', 'Weapon', 2, 4000, 6, NULL, '[{"key":null,"count":null,"misc_desc":"Damage +2 versus droids and vehicles."},{"key":null,"count":null,"misc_desc":"Damage -1 versus organic and other targets."}]'::jsonb, NULL, NULL),
  ('THONTIIN', 'Thontiin Crystal', 'Thontiin Crystal Although long recognized as kyber crystals, thontiin crystals were unheard of as lightsaber cores until recently. Instead, these crystals have been utilized for their unique properties as healing aids, capable of assisting a Jedi healer in easing the pain of a patient and making their treatment easier. The needs of the war have brought these crystals closer to the front lines. After one young Knight’s lightsaber suffered disastrous damage in battle, they attempted to replace their ruined crystal from Ilum with a thontiin crystal. In doing so, the Knight discovered that the crystals’ healing properties were focused through a carried lightsaber in new ways, allowing the bearer to fight through debilitating pain. The healers of the Jedi Order are reluctant to see these sacred artifacts turned into weapons, but the desperate circumstances of the war have caused a handful of them to be repurposed in this manner nevertheless.', 'Weapon', 2, 9000, 9, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":6,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":1,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":null,"count":null,"misc_desc":"Once per encounter, ignore effects of an [B]Easy ([DI])[b] Critical Injury."}]'::jsonb, '[{"key":"DAMADD","count":3,"misc_desc":null},{"key":"CRITSUB","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('ZOPHIS', 'Zophis Crystal', 'Zophis Crystal In ancient days, the Outer Rim world of Zoph was well traveled by the Jedi, and some Padawans would sojourn to the distant world to seek their kyber crystal. As Ilum increased in prominence for the Jedi Order, such visits waned. Now, the world is held by Separatist forces, who would not look kindly upon Jedi crystal seekers. However, some records remain of the unusual kyber crystals gathered on that world, whose unique resonance made for devastating, if unstable, blades. A lightsaber fitted with a Zophis crystal can carve through durasteel plating with ease, but it is vulnerable to fluctuations in power from the crystal core.', 'Weapon', 2, 11000, 10, ARRAY['Lightsaber']::text[], '[{"key":"DAMSET","count":8,"misc_desc":null},{"key":"CRITSET","count":2,"misc_desc":null},{"key":"BREACH","count":2,"misc_desc":null},{"key":"SUNDER","count":null,"misc_desc":null},{"key":"VICIOUS","count":1,"misc_desc":null},{"key":null,"count":null,"misc_desc":"When Sunder quality is activated, damage suffered is increased by one step."},{"key":null,"count":null,"misc_desc":"[TH][TH][TH] or [DE] may be spent to disable the weapon until the wielder''s next turn."}]'::jsonb, '[{"key":"DAMADD","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('SQUADTACT', 'Squad Tactical Systems', 'Squad Tactical Systems Sensor and comm systems are common installations on armor, but some groups take the practice a step further, equipping all their members with uniform packages designed to work in tandem. Squads of clone troopers and planetary militia are the most common users of these systems, but even groups of bounty hunters sometimes avail themselves of the advantages provided by operating in tandem. These sensor packages share information with all other nearby squad members equipped with the same gear, enhancing awareness and communication. This attachment may be installed in the helmet of any armor. Models Include: Fabritech Mk.II “Crosslink” Sensors.', 'Armor', 1, 2000, 5, NULL, '[{"key":null,"count":null,"misc_desc":"Add [BO] to Perception and Vigilance checks while within medium range of one or more allies also using armor with this attachment."},{"key":null,"count":null,"misc_desc":"Includes integrated comlink."}]'::jsonb, '[{"key":"PERC","count":1,"misc_desc":null},{"key":"VIGIL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('PHYSENH', 'Physiological Enhancement System', 'Physiological Enhancement System These advanced, custom-tailored systems provide medical diagnostics, ergonomic adjustments, and powered support systems tuned to the wearer’s motor functions. Stress and pain are greatly reduced by heart-rate regulation and temperature-control systems, and common physical tasks require considerably less effort. These benefits come at a significant cost, as the systems involved require careful calibration to the wearer’s specific needs and physique. Although physiological support systems are normally tailored to individual physiology, they can be produced for clones using a standardized template, greatly reducing the cost. As such, the first cost listed is for clones, while the second, higher price is for a custom support system. This attachment may only be installed on fully enclosed suits of armor, such as laminate, clone trooper, or heavy battle armor. Models Include: Creshaldyne Industries LV-2 “Bio-Strong” Support Suite.', 'Armor', 2, 10000, 7, ARRAY['Full Body']::text[], '[{"key":null,"count":null,"misc_desc":"Reduce strain suffered involuntarily by 1, to minimum of 1."},{"key":null,"count":null,"misc_desc":"Adds [BO] to all Athletics, Coordination, and Resilience checks."}]'::jsonb, '[{"key":"ATHL","count":1,"misc_desc":null},{"key":"COORD","count":1,"misc_desc":null},{"key":"RESIL","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('REVENGARMOR', 'Reverse Engineering', 'Reverse Engineering After working on the item, vehicle, or ship, the character’s comprehension of its technology becomes deep enough to rebuild it even better. The device has its number of hard points increased by one. This cannot be selected more than once per item. Note: Use this attachment on armor when you select the "Reverse Engineering" result from the chart on page 71.', 'Armor', 0, 0, 0, NULL, '[{"key":"HPADD","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('REVENGWEAP', 'Reverse Engineering', 'Reverse Engineering After working on the item, vehicle, or ship, the character’s comprehension of its technology becomes deep enough to rebuild it even better. The device has its number of hard points increased by one. This cannot be selected more than once per item. Note: Use this attachment on weapons when you select the "Reverse Engineering" result from the chart on page 71.', 'Weapon', 0, 0, 0, NULL, '[{"key":"HPADD","count":1,"misc_desc":null}]'::jsonb, NULL, NULL),
  ('BAYONET', 'Bayonet', 'Bayonet In the heat of combat, a ranged conflict can quickly turn into a melee. While most soldiers carry some sort of melee weapon, the ability to also use a rifle in hand-to-hand combat can enable a trooper to act without thinking. A bayonet makes this a natural process and gives a weapon more reach and force than a simple knife. This attachment can only be used on rifle- and carbine-sized weapons. Models Include: SoroSuub Mk IX Bayonet, BlasTech B-3 Field Knife.', 'Weapon', 1, 50, 1, ARRAY['Rifle','Carbine','Heavy Rifle']::text[], '[{"key":null,"count":null,"misc_desc":"Adds a bayonet profile to the weapon."}]'::jsonb, '[{"key":"DEFENSIVE","count":1,"misc_desc":null},{"key":"PIERCE","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('CATFAILMOD', 'Catastrophic Failure Modification', 'Catastrophic Failure Modification Despite their deadliness, lightsabers are famously reliable for a trained user. However, it is possible for an expert in lightsaber construction to bypass the weapon''''s normal safeguards in order to overload it, such as by inverting the emitter matrix, releasing a massive amount of plasma energy. For a Jedi to even consider this course of action, the situation must be truly dire.', 'Weapon', 0, NULL, NULL, ARRAY['Lightsaber']::text[], '[{"key":null,"count":null,"misc_desc":"When lightsaber is activated, it overloads, causing it to detonate at the end of the following round, dealing 20 damage with Breach 1 and Vicious 4, to all characters and objects within short range.  The lightsaber, but not the crystal, is destroyed in the processes."}]'::jsonb, NULL, NULL),
  ('CLONEBIN', 'Clone Polarized Electrobinoculars', 'Clone Polarized Electrobinoculars Some clone troopers mount a pair of electrobinoculars to their helmet on a visor. These can be quickly lowered to the helmet''''s viewport to observe a distant target. The standard set of polarized electrobinoculars includes light filtering as well as image sharpening and stabilization. The Grand Army of the Republic-issue are battle hardened and every bit as durable as the other components of clone trooper armor. Models Include: Ziko 50C Macrovisor.', 'Armor', 1, 500, 4, NULL, '[{"key":null,"count":null,"misc_desc":"Adds [BO] to all sight-based Perception checks."},{"key":null,"count":null,"misc_desc":"Removes [SE] from Perception checks due to distance or low-light conditions."}]'::jsonb, '[{"key":"PERC","count":1,"misc_desc":null}]'::jsonb, NULL),
  ('HAIRTRIG', 'Hair Trigger', 'Hair Trigger Many pistols are designed to cycle and fire as quickly as the trigger can be depressed. Replacing the standard firing mechanism with one that is more responsive allows the wielder to fire substantially more often. Hair triggers can only be installed on Ranged (Light) pistols that lack the Auto-fire quality. Models Include: Morellian MWC-HS Hyper Trigger, BlasTech Industries 009 Fastshot.', 'Weapon', 1, 250, 2, NULL, '[{"key":"LINKED","count":1,"misc_desc":null},{"key":"INACCURATE","count":2,"misc_desc":null}]'::jsonb, '[{"key":"INACCURATE","count":-1,"misc_desc":null}]'::jsonb, NULL),
  ('AMPCHAMBER', 'Amplifying Chamber', 'Amplifying Chamber A blaster fires using energy to excite a small amount of volatile gas into an explosive plasma. That transformation occurs within the weapon''''s chamber, which tightly controls the quantity and ratio of both the gas and the energy. A larger, reinforced chamber enables the weapon to emit a significantly more powerful blast that can inflict its damage over a larger area. Over time, this increases the wear on the weapon and can lead to component breakdown, but most wielders are more than willing to accept this cost for the increase in effectiveness. This attachment can only be installed on blasters Models Include: Rothana RX-99 AmpChamber, BlasTech A-13 Acceleration Chamber.', 'Weapon', 1, 350, 4, ARRAY['Blaster']::text[], '[{"key":"BLAST","count":4,"misc_desc":null},{"key":null,"count":null,"misc_desc":"Adds [SE] to all Mechanics checks to maintain or repair this weapon."}]'::jsonb, '[{"key":"DAMADD","count":1,"misc_desc":null},{"key":"BLAST","count":5,"misc_desc":null}]'::jsonb, NULL),
  ('WHIPTHROW', 'Whipcord Thrower', 'Whipcord Thrower A whipcord thrower quickly deploys a length of high-tensile-strength cable, firing it over a distance in order to secure a target. Its convenient armor mounting allows the user to act quickly, whether to arrest their own freefall, secure a loose object, or entangle a surprised opponent. Models Include: Jeron Hookless Grapplers, Soro-Suub Whipcord Thrower.', 'Armor', 1, 600, 1, NULL, '[{"key":null,"count":null,"misc_desc":"Reduces the difficulty of climbing by one."},{"key":null,"count":null,"misc_desc":"May support up to 200 kg."},{"key":null,"count":null,"misc_desc":"May be used as a weapon."}]'::jsonb, NULL, NULL),
  ('PERVIBROSAW', 'Personal Vibrosaw', 'Personal Vibrosaw Troopers may have to pass through a broad range of environments when on a mission or in pursuit of a target. Sometimes, this requires cutting through forest undergrowth or cutting through a bulkhead so that a unit can quickly bypass critical security systems. To expedite these situations, some troopers mount a personal vibrosaw on a bracer of their armor. When deployed, the diamond-tipped chain rotates rapidly around a thin blade capable of cutting through virtually any material. In extreme situations, the vibrosaw may also be used as a weapon, but its rotating blades make it cumbersome to wield. Models Include: Greel Mk VI Vibrosaw.', 'Armor', 1, 900, 1, NULL, '[{"key":null,"count":null,"misc_desc":"Adds a vibrosaw that can quickly cut through most materials in two or three rounds."},{"key":null,"count":null,"misc_desc":"Adds a vibrosaw weapon profile."}]'::jsonb, NULL, NULL),
  ('PLASMASHIELD', 'Portable Plasma Shield', 'Portable Plasma Shield Armor and weapon designs oppose one another in a cycle of endless escalation. Not surprisingly, many warriors seek out means to enhance their defenses in hopes that it will leave them free to make additional attacks. A small defensive shield can provide a substantial upgrade. Energy shields take this a step further, offering a near-impenetrable defense while requiring much less weight and bulk than a more traditional shield. A forearm-mounted plasma shield''''s biggest limitation is its size. One capable of completely protecting the wearer requires a bulky emitter and energy source. It can also interfere with the soldier''''s own weapons, making striking a blow awkward around the edge of the shield. Models Include: Mili-Corp PS-8C Plasma Buckler, Krail 99 Guardian System', 'Armor', 2, 2500, 4, NULL, '[{"key":null,"count":null,"misc_desc":"May be activated or deactivated as an incidental."},{"key":null,"count":null,"misc_desc":"When active, cannot wield two-handed weapons."},{"key":"DEFENSIVE","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DEFENSIVE","count":2,"misc_desc":null},{"key":"DEFLECTION","count":3,"misc_desc":null}]'::jsonb, NULL),
  ('RETWRIST', 'Retractable Wrist Blades', 'Retractable Wrist Blades Knives are among the most universally developed and broadly useful tools. While its combat function is obvious, knives are also routinely used for modifying equipment, as makeshift prybars, for escaping restraints, and for countless other applications. Not surprisingly, many warriors like to have a blade readily at hand. Mounting retractable blades on one or both forearms of an armored suit provides a solution that is immediately available. In some cases, the mount point is further reinforced, transforming the forearm blade mount into a small buckler. Models Include: Merr-Sonn SB-7 Spring Blades, Dolmax Model 9 Wrist Knife.', 'Armor', 1, 150, 1, NULL, '[{"key":null,"count":null,"misc_desc":"Armor incorporates a wrist blade that can be readied as an incidental."}]'::jsonb, '[{"key":"DEFENSIVE","count":2,"misc_desc":null}]'::jsonb, NULL),
  ('MANDOCHAMBER', 'Mandalorian Chamber', 'Mandalorian Chamber Many Mandalorian warriors customize their gear to an extraordinary degree. Some choose to go so far as to adjust the settings on their blaster''''s chamber, carefully manipulating the ratios of the volatile gas and energy mix. Reinforcing these chambers or adjusting the component''''s size can increase a weapon''''s stopping power or range. A relatively recent innovation commonly known as the Mandalorian chamber, which has become popular among these soldiers, enables the blaster to simultaneously apply characteristics of both the deadly and stun settings. This attachment can only be installed on blasters. Models Include: None.', 'Weapon', 1, 250, 5, ARRAY['Blaster']::text[], '[{"key":"STUN","count":3,"misc_desc":null},{"key":"RANGESUB","count":1,"misc_desc":null}]'::jsonb, '[{"key":"DISORIENT","count":3,"misc_desc":null},{"key":"STUN","count":2,"misc_desc":null},{"key":"RANGEADD","count":1,"misc_desc":null}]'::jsonb, NULL)
